export const ROUTER_CORE_MJS = "/**\n * router-core.mjs — single source of truth for skill/agent routing and gating.\n *\n * Ports `~/.claude/hooks/skill-router.sh` (v3.2) and `~/.claude/hooks/usage-tracker.sh`\n * into cross-platform Node ESM, and unifies them with the pre-existing\n * `gate/claude/skill-gate-lib.mjs` scorer (which drifted from a hand-copied opencode\n * twin). Every fs/env/home/cwd/spawn/clock/path dependency is injectable via `Deps` —\n * nothing in this file reads the real `process.env`, `os.homedir()`, `process.cwd()`,\n * or the real filesystem/network/clock EXCEPT inside `defaultDeps()`, which is the\n * only place those real bindings are touched.\n *\n * Pure Node ESM, no third-party deps, cross-platform (every path builder accepts an\n * injectable `PathImpl` so win32 behaviour is assertable from a posix host).\n *\n * HERMETICITY (W3): every exported function below REQUIRES `deps` explicitly — there is\n * no `deps = defaultDeps()` default anywhere except on `defaultDeps` itself. A default\n * parameter here would let any forgetful caller silently fall through to the real\n * fs/env/homedir/cwd, exactly the footgun `src/paths.ts`'s `opencodeBase` doc-comment\n * warns about. Only the two Claude-hook `main(stdinString, deps = defaultDeps())`\n * entrypoints (`gate/claude/skill-router.mjs`, `gate/claude/skill-usage-tracker.mjs`) and\n * the opencode plugin shell's top-level `defaultDeps()` call are allowed to touch the real\n * bindings — every other caller (including tests) must inject `deps` explicitly.\n *\n * DELIBERATE DEVIATION FROM BASH (W1): `skill-router.sh:281-310` checks `DETECTED_TECH`\n * FIRST and lets it override a HARD/SOFT local match unconditionally. This port instead\n * treats a strong LOCAL index match (HARD/SOFT, computed from the user's own installed\n * skills/agents) as a higher-confidence signal than a keyword-substring guess against the\n * ~50-entry `TECH_KEYWORDS` map, so the tech hint only surfaces in the fallback\n * (HINT/none) branch — see `gate/claude/skill-router.mjs`'s `run()`. Rationale: a mention\n * of \"react\" inside an otherwise strongly-matched prompt (e.g. \"please cache it correctly\n * today with react\") should not silently discard a real `[OBLIGATORIO]` match in favor of\n * a generic \"go run npx skills find\" nudge. Pinned by\n * `src/router-hookio.test.ts`'s \"a HARD local match wins over a detected-tech hint (W1)\".\n */\n\nimport * as nodeFs from \"node:fs\";\nimport { homedir as nodeHomedir } from \"node:os\";\nimport nodePath from \"node:path\";\nimport { spawnSync as nodeSpawnSync } from \"node:child_process\";\nimport { createHash } from \"node:crypto\";\nimport { ES_EN, normalizeEs, singularizeEs } from \"./lexicon.mjs\";\n\n/**\n * Add the English terms a Spanish token stands for, so the prompt and the (English) skill\n * descriptions finally share vocabulary. Original tokens are always kept, so an English\n * prompt scores exactly as it did before — the lexicon can only add signal, never remove it.\n *\n * Unknown words pass through untouched. The router never invents a match it cannot justify\n * from the user's own words.\n */\nexport function expandQuery(tokens) {\n  const out = [];\n  const seen = new Set();\n  const push = (t) => {\n    if (t && !seen.has(t)) {\n      seen.add(t);\n      out.push(t);\n    }\n  };\n\n  for (const raw of tokens) {\n    push(raw);\n    const norm = normalizeEs(raw);\n    const hit = ES_EN[norm] || ES_EN[singularizeEs(norm)];\n    if (hit) for (const en of hit) push(en);\n  }\n  return out;\n}\n\n/**\n * @typedef {object} FsLike   subset actually used — a plain object literal satisfies it\n * @property {(p:string)=>boolean} existsSync\n * @property {(p:string,enc:string)=>string} readFileSync\n * @property {(p:string,data:string)=>void} writeFileSync\n * @property {(p:string,data:string)=>void} appendFileSync\n * @property {(p:string,o?:{recursive?:boolean})=>void} mkdirSync\n * @property {(p:string)=>string[]} readdirSync            // names only; NEVER withFileTypes\n * @property {(p:string)=>{isDirectory():boolean,isFile():boolean,mtimeMs:number,size:number}} statSync // FOLLOWS symlinks (skills are links)\n * @property {(p:string,o?:{force?:boolean})=>void} rmSync\n * @property {(from:string,to:string)=>void} renameSync     // POSIX/NTFS-atomic; used for index writes (K4a)\n *\n * @typedef {object} Deps\n * @property {FsLike} fs\n * @property {Record<string,string|undefined>} env\n * @property {string} home        // never os.homedir() inside this module\n * @property {string} cwd         // never process.cwd() inside this module\n * @property {(cmd:string,args:string[],o:object)=>{stdout:string,status:number}} spawn\n * @property {()=>number} now     // ms epoch; frozen in tests\n * @property {import(\"node:path\").PlatformPath} path\n * @property {(msg:string)=>void} warn  // C4: side-channel diagnostic (stderr in prod) for\n *   hooks whose stdout contract must stay empty/unaffected (e.g. skill-usage-tracker.mjs)\n *   — fail-open must never mean fail-SILENT just because stdout can't carry the signal.\n */\n\n/**\n * Real bindings. The ONLY place `node:fs` / `node:os` / `node:path` /\n * `node:child_process` / `node:crypto` are touched in this module.\n * Intentionally NOT unit-tested directly (calling it would read the real\n * `homedir()`, violating the hermetic-test rule) — exercised only indirectly\n * via the hook entrypoints' shims and manual smoke checks.\n * @returns {Deps}\n */\nexport function defaultDeps() {\n  return {\n    fs: {\n      existsSync: nodeFs.existsSync,\n      readFileSync: nodeFs.readFileSync,\n      writeFileSync: nodeFs.writeFileSync,\n      appendFileSync: nodeFs.appendFileSync,\n      mkdirSync: nodeFs.mkdirSync,\n      readdirSync: nodeFs.readdirSync,\n      statSync: nodeFs.statSync,\n      rmSync: nodeFs.rmSync,\n      renameSync: nodeFs.renameSync,\n    },\n    env: process.env,\n    home: nodeHomedir(),\n    cwd: process.cwd(),\n    spawn: nodeSpawnSync,\n    now: () => Date.now(),\n    path: nodePath,\n    warn: (msg) => {\n      try {\n        process.stderr.write(String(msg) + \"\\n\");\n      } catch {\n        // stderr itself unwritable — nothing more we can do, must not throw\n      }\n    },\n  };\n}\n\n// ============================================================\n// P1 — primitives: STOPWORDS / tokenize / bigrams / classify\n// ============================================================\n\n// Ported verbatim from `gate/claude/skill-gate-lib.mjs` (L28-40) — the CORRECT,\n// complete list (source of truth per AC-5). The opencode-side hand copy this\n// change deletes was missing the accented `también`, silently turning a\n// `suggested` result into `required` via the LEADER fallback.\nexport const STOPWORDS = new Set([\n  // EN\n  \"the\", \"and\", \"for\", \"with\", \"that\", \"this\", \"you\", \"your\", \"are\", \"can\",\n  \"have\", \"has\", \"was\", \"will\", \"how\", \"what\", \"why\", \"when\", \"where\", \"into\",\n  \"from\", \"then\", \"than\", \"not\", \"but\", \"all\", \"any\", \"get\", \"use\", \"using\",\n  \"please\", \"make\", \"want\", \"need\", \"help\", \"let\", \"let's\", \"lets\", \"add\",\n  // ES\n  \"que\", \"los\", \"las\", \"una\", \"uno\", \"por\", \"con\", \"para\", \"como\", \"esto\",\n  \"esta\", \"este\", \"eso\", \"porque\", \"pero\", \"todo\", \"todos\", \"toda\", \"todas\",\n  \"muy\", \"mas\", \"más\", \"hacer\", \"haz\", \"hazlo\", \"quiero\", \"porfavor\", \"porfa\",\n  \"favor\", \"mira\", \"listo\", \"ahora\", \"tambien\", \"también\", \"aplica\", \"aplicas\",\n  \"sabes\", \"algo\", \"veo\", \"correcto\", \"aca\", \"acá\", \"aqui\", \"aquí\", \"utiliza\",\n]);\n\n// K5: ported VERBATIM from `skill-router.sh:138`'s own `STOPWORDS` bash string — a\n// DIFFERENT, materially smaller list than the gate's `STOPWORDS` above (e.g. it keeps\n// \"proyecto\", \"de\", \"con\", \"el\", \"puedes\", \"gracias\", \"dime\", \"create\", \"could\"/\"would\"/\n// \"should\" out of scoring, several of which the gate's list does NOT). `scoreRouter`\n// (the bash `awk` scoring formula) must tokenize with THIS list — reusing the gate's list\n// would let tokens the real bash router treats as noise leak into scoring, silently\n// diverging from `skill-router.sh`'s actual output on ordinary prompts.\nexport const ROUTER_STOPWORDS = new Set([\n  \"el\", \"la\", \"los\", \"las\", \"un\", \"una\", \"de\", \"del\", \"y\", \"o\", \"que\", \"como\", \"para\",\n  \"por\", \"con\", \"sin\", \"en\", \"sobre\", \"es\", \"son\", \"este\", \"esto\", \"mi\", \"tu\", \"su\", \"se\",\n  \"lo\", \"le\", \"me\", \"te\",\n  \"the\", \"and\", \"or\", \"for\", \"with\", \"this\", \"that\", \"can\", \"could\", \"would\", \"should\",\n  \"help\", \"need\", \"want\", \"make\", \"create\", \"get\",\n  \"puedes\", \"favor\", \"please\", \"thanks\", \"gracias\", \"hacer\", \"dime\", \"voy\", \"proyecto\",\n  \"tener\", \"haria\", \"vas\", \"hago\", \"pasos\", \"primero\", \"antes\", \"empezar\",\n]);\n\n/** Lowercase, split on non-alnum (incl. Spanish diacritics), drop len<3, drop stopwords.\n * `stopwords` defaults to the GATE's list (`scoreGate`'s caller); `scoreRouter` passes\n * `ROUTER_STOPWORDS` explicitly (K5) — the two scorers intentionally use DIFFERENT\n * stopword sets, matching their respective bash sources. */\n/**\n * Two-letter tokens that are real technical signals, not noise.\n *\n * The `length >= 3` filter exists to kill \"de\", \"el\", \"un\" — and it was also killing the\n * strongest domain terms we have. Concretely: for \"necesito armar un componente de UI con\n * buen pulido\", emil-design-eng — whose description literally reads \"UI polish, component\n * design\" — scored 2 against a SOFT_MIN of 3 and was dropped. It lost by exactly the point\n * that \"ui\" would have contributed.\n */\nexport const SHORT_TERMS = new Set([\"ui\", \"ux\", \"db\", \"ci\", \"cd\", \"qa\", \"ai\", \"js\", \"ts\", \"go\", \"os\", \"id\"]);\n\n/**\n * How many scored candidates reach classify().\n *\n * The bash original ended with `head -3`, and the port kept it faithfully. That cap made\n * the documented contract false: REQUIRED is capped, SUGGESTED is supposed to be uncapped\n * (\"if five skills genuinely help, all five are surfaced\"), but classify() never saw more\n * than three rows — a complementary skill ranked fourth was discarded before anyone could\n * suggest it.\n *\n * Widening the pool does NOT loosen enforcement. `required` is decided by a SCORE threshold\n * (>= STRONG), never by rank, so a wider pool can only add SUGGESTED entries. Nothing new\n * can block a turn. The cost is a handful of extra skill names in the prompt preamble.\n */\nexport const CANDIDATE_POOL = 10;\n\nexport function tokenize(text, stopwords = STOPWORDS) {\n  return (text || \"\")\n    .toLowerCase()\n    .split(/[^a-z0-9áéíóúñ]+/i)\n    .filter((t) => (t.length >= 3 || SHORT_TERMS.has(t)) && !stopwords.has(t));\n}\n\n/** \"a_b\"-joined adjacent token pairs, order preserved. Pure. */\nexport function bigrams(tokens) {\n  const out = [];\n  for (let i = 0; i < tokens.length - 1; i++) {\n    out.push(`${tokens[i]}_${tokens[i + 1]}`);\n  }\n  return out;\n}\n\n// Score at/above which a match is strong enough to HARD-enforce (gate blocks).\nexport const STRONG = 6;\n// Minimum score to surface at all (as a soft suggestion).\nexport const SOFT_MIN = 3;\n\n/**\n * Split scored matches into the HARD-enforced `required` set and the SOFT\n * `suggested` set. Ported verbatim from `skill-gate-lib.mjs` `classify()` (L137-147).\n *   required  = score >= STRONG, capped at hardCap.\n *   LEADER=5 fallback: if nothing is \"strong\" but there's a clear dominant leader\n *   (score >= LEADER), enforce just that one.\n */\nexport function classify(scored, { hardCap = 4 } = {}) {\n  let required = scored.filter((s) => s.score >= STRONG).slice(0, hardCap).map((s) => s.name);\n  const LEADER = 5;\n  if (required.length === 0 && scored[0] && scored[0].score >= LEADER) {\n    required = [scored[0].name];\n  }\n  const suggested = scored.filter((s) => !required.includes(s.name)).map((s) => s.name);\n  return { required, suggested };\n}\n\n// ============================================================\n// P2 — scoring: scoreRouter (skill-router.sh awk math) / scoreGate (skill-gate-lib.mjs math)\n// ============================================================\n\n/**\n * EXACT bash math from `skill-router.sh`'s `score_index()` awk block (L156-181).\n * Iterates the FILTERED token array once PER OCCURRENCE (not deduplicated — a\n * token repeated 3x in the prompt contributes its per-occurrence score 3x over,\n * a verbatim bash quirk that MUST be preserved). Returns top-3, desc-sorted,\n * stable on ties (first-inserted wins).\n *\n * Per-token: desc-substring occurrence count (capped at 3) x1, plus name-substring\n * hit x3 (name compared with `-`/`_` replaced by spaces, like the bash `lname`).\n * Per-bigram (independent, additive): desc match +2, name match +2.\n */\n/**\n * Whole-word matching.\n *\n * The bash original matched with grep-style substring containment. For long English\n * tokens that is harmless; for short ones it is poison. The Spanish word \"mal\"\n * (\"bad\") — which shows up in a great many real prompts — is a substring of\n * \"deciMAL\", \"norMAL\", \"forMAL\", \"aniMAL\". Junk skills cleared the HARD threshold\n * and got injected as [OBLIGATORIO], spending context on skills unrelated to the task.\n *\n * `\\b` in JS is ASCII-only, so it would split on the accents that Spanish prompts are\n * full of (\"diseño\", \"animación\"). The boundary is expressed with lookarounds over an\n * explicit Latin-1/Latin-Extended-A word class instead.\n */\nconst WORD_CHAR = \"[A-Za-z0-9\\\\u00C0-\\\\u024F]\";\n\nfunction wordPattern(term, flags) {\n  const escaped = term.replace(/[.*+?^${}()|[\\]\\\\]/g, \"\\\\$&\");\n  return new RegExp(`(?<!${WORD_CHAR})${escaped}(?!${WORD_CHAR})`, flags);\n}\n\nexport function hasWord(haystack, term) {\n  if (!term) return false;\n  return wordPattern(term, \"\").test(haystack);\n}\n\nexport function countWord(haystack, term, cap = Infinity) {\n  if (!term) return 0;\n  const matches = haystack.match(wordPattern(term, \"g\"));\n  return matches ? Math.min(matches.length, cap) : 0;\n}\n\nexport function scoreRouter(prompt, index, _deps) {\n  // K5: tokenize with the ROUTER's own stopword list (skill-router.sh:138), NOT the\n  // gate's — see the ROUTER_STOPWORDS doc comment above.\n  // Expand Spanish terms into the English vocabulary the skill descriptions are written\n  // in. Without this the prompt and the index share no words and noise wins outright.\n  const filtered = expandQuery(tokenize(prompt, ROUTER_STOPWORDS));\n  if (filtered.length === 0) return [];\n  const bg = bigrams(filtered);\n\n  const rows = [];\n  index.forEach((row, insertionIndex) => {\n    const desc = (row.desc || \"\").toLowerCase();\n    const lname = row.name.toLowerCase().replace(/[-_]/g, \" \");\n    let score = 0;\n\n    for (const t of filtered) {\n      if (!t) continue;\n      // Whole-word, capped at 3 (the awk original capped occurrences the same way).\n      score += countWord(desc, t, 3);\n      if (hasWord(lname, t)) score += 3;\n    }\n\n    for (const pair of bg) {\n      if (!pair) continue;\n      const spaced = pair.replace(/_/g, \" \");\n      if (hasWord(desc, spaced)) score += 2;\n      if (hasWord(lname, spaced)) score += 2;\n    }\n\n    if (score > 0) rows.push({ name: row.name, score, insertionIndex });\n  });\n\n  rows.sort((a, b) => b.score - a.score || a.insertionIndex - b.insertionIndex);\n  return rows.slice(0, CANDIDATE_POOL).map((r) => ({ name: r.name, score: r.score }));\n}\n\n// Ambient/meta tokens that describe the tooling itself, not the task domain.\n// Ported verbatim from `skill-gate-lib.mjs` (L46-55).\nexport const AMBIENT = new Set([\n  \"claude\", \"code\", \"opencode\", \"skill\", \"skills\", \"hook\", \"hooks\", \"gate\",\n  \"harness\", \"tool\", \"tools\", \"plugin\", \"plugins\", \"run\", \"corre\", \"corré\",\n  \"prueba\", \"pruebalo\", \"pruébalo\", \"probar\", \"test\", \"tests\", \"testing\",\n  \"instalador\", \"instaladores\", \"installer\", \"install\", \"funciona\", \"aplicar\",\n  \"aplicalo\", \"aplícalo\", \"harnes\", \"harneses\",\n  // URL / VCS chrome — a pasted link must not force domain skills.\n  \"github\", \"gitlab\", \"bitbucket\", \"com\", \"http\", \"https\", \"www\", \"git\",\n  \"repo\", \"repos\", \"link\", \"url\", \"raw\", \"main\", \"master\", \"branch\",\n]);\n\n/**\n * EXACT current gate math, moved VERBATIM from `skill-gate-lib.mjs`'s `scoreSkills()`:\n * name-token exact = 3 (0.5 if AMBIENT), name-substring = 1.5 (0 if AMBIENT),\n * desc substring = 1 (0.25 if AMBIENT). Tokens deduplicated via `Set` BEFORE scoring\n * (unlike `scoreRouter`). `opts.minScore` defaults to SOFT_MIN, matching the current\n * `scoreSkills`'s `score >= SOFT_MIN` filter (a lower `minScore` is a test-only knob\n * to inspect the raw pre-filter score).\n */\nexport function scoreGate(prompt, index, { max = 12, minScore = SOFT_MIN } = {}) {\n  const tokens = [...new Set(tokenize(prompt))];\n  if (tokens.length === 0) return [];\n\n  const scored = [];\n  for (const { name, desc } of index) {\n    const nameFlat = name.toLowerCase().replace(/[-_]/g, \"\");\n    const nameTokens = new Set(name.toLowerCase().split(/[-_]/));\n    let score = 0;\n    for (const t of tokens) {\n      const amb = AMBIENT.has(t);\n      if (nameTokens.has(t)) score += amb ? 0.5 : 3;\n      else if (nameFlat.includes(t)) score += amb ? 0 : 1.5;\n      if (desc.includes(t)) score += amb ? 0.25 : 1;\n    }\n    if (score >= minScore) scored.push({ name, desc, score });\n  }\n  scored.sort((a, b) => b.score - a.score);\n  return scored.slice(0, max);\n}\n\n// ============================================================\n// P3 — index build / load / needsRebuild / ensureIndex\n// ============================================================\n//\n// NOTE ON PATH BUILDERS: this section duplicates a small subset of the pure path\n// logic that also lives (as TypeScript) in `src/paths.ts`. That duplication is\n// intentional (see design.md): router-core.mjs must stay self-contained so it can\n// be inlined verbatim into the generated opencode plugin — it cannot import a .ts\n// file from outside the repo. Every builder here takes `deps` (home + path) rather\n// than raw `home`/`p`, matching this module's injectable-deps convention.\n\nfunction claudeDirOf(deps) {\n  return deps.path.join(deps.home, \".claude\");\n}\nfunction skillsDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \"skills\");\n}\nfunction agentsDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \"agents\");\n}\nfunction routerCacheDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \".router-cache\");\n}\nfunction skillsIndexPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"skills-index.tsv\");\n}\nfunction agentsIndexPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"agents-index.tsv\");\n}\nfunction npxCacheDirOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"npx-cache\");\n}\nfunction lastSuggestionPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"last-suggestion.json\");\n}\nfunction routerStateDirOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"state\");\n}\n\n// Public path-builder wrappers (design.md's \"paths\" export bucket, Modules table).\n// P7 hook entrypoints (gate/claude/skill-router.mjs, skill-usage-tracker.mjs) live\n// outside this module and need these exact paths to loadIndex()/read/write the same\n// files ensureIndex()/adjust()/recordUse() already compute internally. Additive-only\n// (no existing export changed) — verified by re-running the full P0-P6 suite (78\n// pass, 0 fail) after this addition.\nexport function skillsIndexPath(deps) {\n  return skillsIndexPathOf(deps);\n}\nexport function agentsIndexPath(deps) {\n  return agentsIndexPathOf(deps);\n}\nexport function lastSuggestionPath(deps) {\n  return lastSuggestionPathOf(deps);\n}\n\n/**\n * Suggestion (QA iteration 2): fail-open (never throws), but now RETURNS the error\n * (`null` on success) instead of swallowing it — a mkdir failure here used to surface\n * only as a confusing, misattributed write error one step later.\n */\nfunction ensureDirSafe(deps, dir) {\n  try {\n    deps.fs.mkdirSync(dir, { recursive: true });\n    return null;\n  } catch (e) {\n    return (e && e.message) || String(e);\n  }\n}\n\n/**\n * Parse the `description:` frontmatter field, matching the bash `awk` extraction for the\n * common single-line case, PLUS (W6, a deliberate improvement over the bash source — the\n * bash `awk` has the exact same limitation, so this is not a regression) a YAML\n * block-scalar (`description: |`, `|-`, `|+`, `>`, `>-`, `>+`) continuation join: every\n * subsequent indented line is collected and space-joined until indentation ends. Without\n * this, a skill using this extremely common YAML style (confirmed against the real\n * installed `~/.claude/skills/academic-researcher/SKILL.md`) indexes as the literal\n * single-character description `\"|\"`, silently killing routing for it.\n */\nfunction extractDescription(content) {\n  const lines = (content || \"\").split(\"\\n\");\n  const idx = lines.findIndex((l) => /^description:/.test(l));\n  if (idx === -1) return \"\";\n  let rest = lines[idx].replace(/^description:\\s*/, \"\");\n\n  if (/^[|>][+-]?\\s*$/.test(rest.trim())) {\n    const collected = [];\n    for (let i = idx + 1; i < lines.length; i++) {\n      const line = lines[i];\n      if (line.trim() === \"\") {\n        collected.push(\"\");\n        continue;\n      }\n      if (/^\\s/.test(line)) {\n        collected.push(line.trim());\n      } else {\n        break; // indentation ended -> block scalar is done\n      }\n    }\n    rest = collected.filter(Boolean).join(\" \");\n  }\n\n  return rest.replace(/\"/g, \"\").trim().toLowerCase();\n}\n\n/**\n * K4(a): atomic index write — write to a sibling temp file, then `renameSync` it onto the\n * real path. `rename` is atomic on both POSIX and NTFS, so a reader (skill-gate-eval.mjs\n * via `ensureIndex`) can never observe a torn/partial index mid-write. Returns `null` on\n * success, or a string error message on failure (K3) — NEVER throws.\n *\n * C2: `skill-gate-eval.mjs` and `skill-router.mjs` are TWO SEPARATE PROCESSES wired on the\n * SAME UserPromptSubmit event, and Claude Code runs matching hooks in PARALLEL. A shared\n * `${path}.tmp` name meant process B's write could truncate/rewrite the tmp file process A\n * was about to `renameSync` — `rename` itself is atomic, but the SOURCE it publishes was\n * not race-free, so a torn index could still get published atomically. The tmp name is now\n * unique per call (`pid` + random), and a failed write/rename cleans up its own tmp instead\n * of leaving it orphaned.\n */\nfunction atomicWriteIndex(deps, path, data) {\n  const tmp = `${path}.${process.pid}.${Math.random().toString(36).slice(2)}.tmp`;\n  try {\n    deps.fs.writeFileSync(tmp, data);\n    deps.fs.renameSync(tmp, path);\n    return null;\n  } catch (e) {\n    try {\n      deps.fs.rmSync(tmp, { force: true });\n    } catch {\n      // best-effort cleanup; the write/rename error below is what matters\n    }\n    return (e && e.message) || String(e);\n  }\n}\n\n// Directory names pruned BEFORE recursion on the agents walk (never opened at all).\nconst PRUNED_DIR_NAMES = new Set([\"node_modules\"]);\nfunction isPrunedDirName(name) {\n  return PRUNED_DIR_NAMES.has(name) || name.startsWith(\".\");\n}\n\n/**\n * Top-level `<skillsDir>/<name>/SKILL.md` scan only (NFR: no recursion into a skill's\n * internal files). Uses `fs.statSync` (follows symlinks/junctions) — never\n * `lstat`/`dirent.isDirectory` — the exact bash bug (`find` without `-L`) this change\n * fixes. A dangling symlink (statSync throws) is skipped, not crashed. Pure computation,\n * no write — shared by `buildSkillIndex` (writes) and `needsRebuild` (W3: compares this\n * live count against what's currently indexed, to catch deletions mtime can't see).\n */\nfunction computeSkillRows(deps) {\n  const dir = skillsDirOf(deps);\n  const rows = [];\n  let names = [];\n  try {\n    names = deps.fs.readdirSync(dir);\n  } catch {\n    names = [];\n  }\n  for (const name of names) {\n    const skillPath = deps.path.join(dir, name);\n    let st;\n    try {\n      st = deps.fs.statSync(skillPath);\n    } catch {\n      continue; // dangling symlink or race — skip, don't crash\n    }\n    if (!st.isDirectory()) continue;\n    const mdPath = deps.path.join(skillPath, \"SKILL.md\");\n    let mdStat;\n    try {\n      mdStat = deps.fs.statSync(mdPath);\n    } catch {\n      continue;\n    }\n    if (!mdStat.isFile()) continue;\n    let content = \"\";\n    try {\n      content = deps.fs.readFileSync(mdPath, \"utf8\");\n    } catch {\n      continue;\n    }\n    const desc = extractDescription(content) || name;\n    rows.push({ name, desc: desc.toLowerCase() });\n  }\n  return rows;\n}\n\nexport function buildSkillIndex(deps) {\n  const rows = computeSkillRows(deps);\n  const idxPath = skillsIndexPathOf(deps);\n  // Suggestion: `ensureDirSafe` used to swallow its own mkdir error, so a subsequent\n  // unguarded write threw a misleading ENOENT that hid the REAL root cause (mkdir\n  // EACCES/EROFS). Thread the mkdir error into `writeError` first, so `indexError`\n  // reports what actually failed.\n  const mkdirError = ensureDirSafe(deps, routerCacheDirOf(deps));\n  const tsv = rows.map((r) => `${r.name}\\t${r.desc}`).join(\"\\n\") + (rows.length ? \"\\n\" : \"\");\n  const writeError = mkdirError || atomicWriteIndex(deps, idxPath, tsv);\n  return { rows: rows.length, path: idxPath, writeError };\n}\n\n/**\n * Recursive `**\\/*.md` walk of `agentsDir`, PRUNING `node_modules/` and any\n * dot-prefixed directory BEFORE recursing — those directories are never passed\n * to `readdirSync`/`statSync` at all, not merely filtered out of the result\n * (perf: the bash source's plain `find` walked `skills/playwright/node_modules`\n * — thousands of files on every prompt). Pure computation, no write — shared by\n * `buildAgentIndex` (writes) and `needsRebuild` (W3).\n */\nfunction computeAgentRows(deps) {\n  const root = agentsDirOf(deps);\n  const rows = [];\n\n  function walk(dir) {\n    let names = [];\n    try {\n      names = deps.fs.readdirSync(dir);\n    } catch {\n      return;\n    }\n    for (const name of names) {\n      if (isPrunedDirName(name)) continue; // never opened\n      const full = deps.path.join(dir, name);\n      let st;\n      try {\n        st = deps.fs.statSync(full);\n      } catch {\n        continue;\n      }\n      if (st.isDirectory()) {\n        walk(full);\n        continue;\n      }\n      if (st.isFile() && name.toLowerCase().endsWith(\".md\")) {\n        let content = \"\";\n        try {\n          content = deps.fs.readFileSync(full, \"utf8\");\n        } catch {\n          continue;\n        }\n        const base = name.replace(/\\.md$/i, \"\");\n        const desc = extractDescription(content) || base;\n        rows.push({ name: base, desc: desc.toLowerCase() });\n      }\n    }\n  }\n  walk(root);\n  return rows;\n}\n\nexport function buildAgentIndex(deps) {\n  const rows = computeAgentRows(deps);\n  const idxPath = agentsIndexPathOf(deps);\n  const mkdirError = ensureDirSafe(deps, routerCacheDirOf(deps));\n  const tsv = rows.map((r) => `${r.name}\\t${r.desc}`).join(\"\\n\") + (rows.length ? \"\\n\" : \"\");\n  const writeError = mkdirError || atomicWriteIndex(deps, idxPath, tsv);\n  return { rows: rows.length, path: idxPath, writeError };\n}\n\n/** Fail-open TSV loader: malformed lines (no tab, whitespace-only name) are skipped. */\nexport function loadIndex(idxPath, deps) {\n  let content = \"\";\n  try {\n    if (!deps.fs.existsSync(idxPath)) return [];\n    content = deps.fs.readFileSync(idxPath, \"utf8\");\n  } catch {\n    return [];\n  }\n  const rows = [];\n  for (const line of content.split(\"\\n\")) {\n    if (!line.trim()) continue;\n    const tab = line.indexOf(\"\\t\");\n    if (tab === -1) continue; // malformed: no tab character\n    const name = line.slice(0, tab).trim();\n    if (!name) continue; // whitespace-only name\n    const desc = line.slice(tab + 1).trim().toLowerCase();\n    rows.push({ name, desc });\n  }\n  return rows;\n}\n\n/** Recursive newest .md mtime under `dir`, pruning the same dirs as buildAgentIndex. */\nfunction newestMdMtime(dir, deps) {\n  let names;\n  try {\n    names = deps.fs.readdirSync(dir);\n  } catch {\n    return -1;\n  }\n  let max = -1;\n  for (const name of names) {\n    if (isPrunedDirName(name)) continue;\n    const full = deps.path.join(dir, name);\n    let st;\n    try {\n      st = deps.fs.statSync(full);\n    } catch {\n      continue;\n    }\n    if (st.isDirectory()) {\n      const sub = newestMdMtime(full, deps);\n      if (sub > max) max = sub;\n    } else if (name.toLowerCase().endsWith(\".md\")) {\n      if (st.mtimeMs > max) max = st.mtimeMs;\n    }\n  }\n  return max;\n}\n\n/**\n * `needsRebuild(srcDir, idxPath, deps, kind)` — ported from `skill-router.sh`'s\n * `needs_rebuild()`: an existing-but-empty (`0`-byte) index ALWAYS triggers a\n * rebuild attempt (`[[ ! -s \"$idx\" ]]`), regardless of mtimes; otherwise a rebuild\n * is needed iff some `.md` file under `srcDir` is newer than the index.\n *\n * W3: mtime alone is blind to DELETIONS — uninstalling a skill/agent never bumps any\n * SURVIVING file's mtime, so nothing here would ever look \"newer\" and the stale row for\n * the removed entry keeps scoring forever (`skill-gate-eval` would put a no-longer-\n * installed skill in `required`, `readSkillBody` returns \"\" silently, and the Stop gate\n * blocks the turn demanding a Skill() call that cannot succeed). Fixed by ALSO comparing\n * the currently-installed row count (`kind`: \"skill\" -> `computeSkillRows`, \"agent\" ->\n * `computeAgentRows` — the same counting logic each builder uses) against what's actually\n * on disk in the index; any mismatch (shrink OR growth the mtime check somehow missed)\n * triggers a rebuild too.\n */\nexport function needsRebuild(srcDir, idxPath, deps, kind = \"skill\") {\n  let idxStat;\n  try {\n    idxStat = deps.fs.statSync(idxPath);\n  } catch {\n    return true; // missing index -> rebuild\n  }\n  if (idxStat.size === 0) return true; // empty index -> always rebuild\n  const newest = newestMdMtime(srcDir, deps);\n  if (newest === -1) return false; // src dir missing / no md files -> nothing to rebuild from\n  if (newest > idxStat.mtimeMs) return true;\n  const currentRows = (kind === \"agent\" ? computeAgentRows(deps) : computeSkillRows(deps)).length;\n  const indexedRows = loadIndex(idxPath, deps).length;\n  return currentRows !== indexedRows;\n}\n\n/**\n * Orchestrates the skill + agent index builds: rebuilds only when `needsRebuild`\n * is true, and reports `empty:true` whenever the skills index has zero rows\n * (missing dir, zero valid `SKILL.md` entries, or all dangling symlinks) — the\n * precondition for the P7 loud empty-index warning.\n */\nexport function ensureIndex(deps) {\n  const skillsDir = skillsDirOf(deps);\n  const agentsDir = agentsDirOf(deps);\n  const skillIdxPath = skillsIndexPathOf(deps);\n  const agentIdxPath = agentsIndexPathOf(deps);\n\n  let rebuilt = false;\n  // K3: a write failure (EACCES/EROFS/ENOSPC) building either index is captured here,\n  // never thrown and never silently dropped — the caller (skill-router.mjs) turns this\n  // into a LOUD `[ROUTER WARNING]` instead of degrading to an empty, silent suggestion.\n  let indexError = null;\n\n  let skillsExists = false;\n  try {\n    skillsExists = deps.fs.statSync(skillsDir).isDirectory();\n  } catch {\n    skillsExists = false;\n  }\n  if (skillsExists && needsRebuild(skillsDir, skillIdxPath, deps, \"skill\")) {\n    const r = buildSkillIndex(deps);\n    rebuilt = true;\n    if (r.writeError) indexError = `${r.path}: ${r.writeError}`;\n  }\n\n  let agentsExists = false;\n  try {\n    agentsExists = deps.fs.statSync(agentsDir).isDirectory();\n  } catch {\n    agentsExists = false;\n  }\n  if (agentsExists && needsRebuild(agentsDir, agentIdxPath, deps, \"agent\")) {\n    const r = buildAgentIndex(deps);\n    rebuilt = true;\n    if (r.writeError && !indexError) indexError = `${r.path}: ${r.writeError}`;\n  }\n\n  const skills = loadIndex(skillIdxPath, deps);\n  const agents = loadIndex(agentIdxPath, deps);\n  // Suggestion: `empty` only ever reflected the SKILLS index — an installed-but-empty\n  // AGENTS index degraded `[AGENTS]` suggestions to permanent silence with no flag at all\n  // to detect it by. `agentsEmpty` makes that state inspectable too.\n  return {\n    skills: skills.length,\n    agents: agents.length,\n    rebuilt,\n    empty: skills.length === 0,\n    agentsEmpty: agents.length === 0,\n    indexError,\n  };\n}\n\n// ============================================================\n// P4 — memoryDir (impure wrapper; pure projectSlug/memoryDirs duplicated from\n// src/paths.ts on purpose — see the P3 path-builder note above: this module must\n// stay self-contained to be inlined into the generated opencode plugin).\n// ============================================================\n\n/** Slug = absolute cwd, every non-alnum char -> \"-\", one-for-one, no collapsing. */\nfunction projectSlugOf(cwd) {\n  return cwd.replace(/[^A-Za-z0-9]/g, \"-\");\n}\n\n/** Candidate memory dirs, most-specific first. Pure — mirrors src/paths.ts's memoryDirs. */\nfunction memoryDirsOf(deps) {\n  return [\n    deps.path.join(claudeDirOf(deps), \"projects\", projectSlugOf(deps.cwd), \"memory\"),\n    routerStateDirOf(deps),\n  ];\n}\n\n/**\n * Impure wrapper: picks the first EXISTING `memoryDirsOf` candidate, falling back\n * to the 2nd (`routerStateDir`) when the project-memory dir doesn't exist yet.\n */\nexport function memoryDir(home, cwd, deps) {\n  const d = { ...deps, home, cwd };\n  const candidates = memoryDirsOf(d);\n  for (const c of candidates) {\n    let exists = false;\n    try {\n      exists = d.fs.existsSync(c);\n    } catch {\n      exists = false;\n    }\n    if (exists) return c;\n  }\n  return candidates[candidates.length - 1];\n}\n\n// ============================================================\n// P5 — tracker accounting primitives: adjust / recordUse / recordIgnore / shouldIgnore\n// ============================================================\n\nfunction ignoredSkillsPathOf(deps) {\n  return deps.path.join(memoryDir(deps.home, deps.cwd, deps), \"ignored-skills.md\");\n}\n\n/** Fail-open JSON read: malformed/missing/unreadable -> `fallback`, never throws. */\n/**\n * C3: `JSON.parse` succeeds on `null`/`[]`/`\"x\"`/`3` — only a THROW falls back to\n * `fallback`. A truncated/corrupt state file containing e.g. `null` used to make this\n * return `null` itself, and the caller's `stats[name]` then threw a TypeError, swallowed\n * by the tracker's blind catch — worse, in `recordIgnore` the ignored-skills.md append had\n * ALREADY happened before that crash, so `clearSuggestion()` never ran and the same\n * suggestion re-appended on every subsequent tool call, cascading into a runaway HARD\n * escalation. Fixed by validating the parsed value is a genuine plain object; anything else\n * (including `null`/arrays/primitives) is treated exactly like unreadable/malformed JSON —\n * discarded, fallback returned, reported via `error` (never surfaced when the file simply\n * doesn't exist yet — that's the normal first-run case, not a corruption).\n */\nfunction readJsonSafe(deps, path, fallback) {\n  try {\n    if (!deps.fs.existsSync(path)) return { value: fallback, error: null };\n    const raw = deps.fs.readFileSync(path, \"utf8\");\n    const parsed = JSON.parse(raw);\n    if (typeof parsed !== \"object\" || parsed === null || Array.isArray(parsed)) {\n      const kind = parsed === null ? \"null\" : Array.isArray(parsed) ? \"array\" : typeof parsed;\n      return { value: fallback, error: `${path}: corrupt state (expected an object, got ${kind}) — discarded` };\n    }\n    return { value: parsed, error: null };\n  } catch (e) {\n    return { value: fallback, error: `${path}: unreadable/invalid JSON (${(e && e.message) || String(e)}) — discarded` };\n  }\n}\n\n/**\n * `adjust(name, base, deps)` — ported from `skill-router.sh`'s `adjust()`: `+2`\n * when `<memoryDir>/ignored-skills.md` has `>= 3` lines starting with\n * `\"<name> |\"`, else `+0`. Fail-open (AC-14): an unreadable/missing file defaults\n * the bump to `0`, never throws.\n */\nexport function adjust(name, base, deps) {\n  const path = ignoredSkillsPathOf(deps);\n  let content = \"\";\n  try {\n    if (!deps.fs.existsSync(path)) return base;\n    content = deps.fs.readFileSync(path, \"utf8\");\n  } catch {\n    return base; // fail-open\n  }\n  const needle = `${name} |`;\n  const count = content.split(\"\\n\").filter((line) => line.startsWith(needle)).length;\n  return count >= 3 ? base + 2 : base;\n}\n\n/** Increments `tool-stats.json[name].used` by 1 (creates the entry if absent). */\n/**\n * C4: increments `tool-stats.json[name].used`. NEVER throws — a write failure\n * (EACCES/EROFS/ENOSPC) is caught and returned as an error string (`null` on success) so\n * the caller (skill-usage-tracker.mjs's `main`) can surface a `[TRACKER WARNING]` instead\n * of letting it die inside a blind catch with zero signal.\n */\nexport function recordUse(name, deps) {\n  const memDir = memoryDir(deps.home, deps.cwd, deps);\n  const path = deps.path.join(memDir, \"claude-tool-stats.json\");\n  const { value: stats, error: readError } = readJsonSafe(deps, path, {});\n  const entry = stats[name] || { used: 0, ignored: 0 };\n  stats[name] = { ...entry, used: (entry.used || 0) + 1 };\n  ensureDirSafe(deps, memDir);\n  try {\n    deps.fs.writeFileSync(path, JSON.stringify(stats));\n    return readError;\n  } catch (e) {\n    return [readError, `${path}: ${(e && e.message) || String(e)}`].filter(Boolean).join(\"; \");\n  }\n}\n\n/**\n * Appends `\"<name> | <iso-ts> | <score> | <kind> | <snippet>\"` to\n * `ignored-skills.md` (iso-ts from `deps.now()`, never `Date.now()`), increments\n * `tool-stats.json[name].ignored`, truncates `promptSnippet` to 100 chars.\n *\n * C3/C4: NEVER throws. The append happens first (matching the original ordering — the\n * caller's `clearSuggestion()` must still run afterward regardless), and every write is\n * individually guarded so a failure anywhere in this function surfaces as a returned error\n * string instead of an uncaught exception that would leave the caller's suggestion-clear\n * step unreached.\n */\nexport function recordIgnore(name, score, kind, promptSnippet, deps) {\n  const memDir = memoryDir(deps.home, deps.cwd, deps);\n  const ignoredPath = deps.path.join(memDir, \"ignored-skills.md\");\n  const statsPath = deps.path.join(memDir, \"claude-tool-stats.json\");\n  ensureDirSafe(deps, memDir);\n\n  const iso = new Date(deps.now()).toISOString();\n  const snippet = (promptSnippet || \"\").slice(0, 100);\n  const line = `${name} | ${iso} | ${score} | ${kind} | ${snippet}\\n`;\n  let appendError = null;\n  try {\n    deps.fs.appendFileSync(ignoredPath, line);\n  } catch (e) {\n    appendError = `${ignoredPath}: ${(e && e.message) || String(e)}`;\n  }\n\n  const { value: stats, error: readError } = readJsonSafe(deps, statsPath, {});\n  const entry = stats[name] || { used: 0, ignored: 0 };\n  stats[name] = { ...entry, ignored: (entry.ignored || 0) + 1 };\n  try {\n    deps.fs.writeFileSync(statsPath, JSON.stringify(stats));\n    return [appendError, readError].filter(Boolean).join(\"; \") || null;\n  } catch (e) {\n    return [appendError, readError, `${statsPath}: ${(e && e.message) || String(e)}`].filter(Boolean).join(\"; \");\n  }\n}\n\n// Tools whose completion can count as \"ignored the suggestion\" — mirrors\n// usage-tracker.sh's `^(Bash|Edit|Write|Read|Grep|Glob)$` whitelist.\nconst IGNORE_ELIGIBLE_TOOLS = new Set([\"Bash\", \"Edit\", \"Write\", \"Read\", \"Grep\", \"Glob\"]);\nconst IGNORE_AFTER_MS = 30_000;\n\n/**\n * Pure predicate: `{skill, agent}` independently — a suggestion can log an\n * ignored skill and NOT an ignored agent, or vice versa. Requires >30s elapsed,\n * `toolName` in the tracked whitelist, and the respective score `>= SOFT_MIN`.\n */\nexport function shouldIgnore(nowMs, suggestion, toolName) {\n  // Suggestion (QA iteration 2): `nowMs - suggestion.ts` is `NaN` whenever `ts` is\n  // missing/non-numeric, and `NaN > IGNORE_AFTER_MS` is ALWAYS `false` — silently\n  // disabling ignore-tracking FOREVER for that suggestion, with zero error/warning. A\n  // missing/invalid `ts` is treated as \"old enough\" (elapsed = Infinity), not \"never old\n  // enough\".\n  const ts = suggestion && suggestion.ts;\n  const elapsed = Number.isFinite(ts) ? nowMs - ts : Infinity;\n  const eligible = IGNORE_ELIGIBLE_TOOLS.has(toolName) && elapsed > IGNORE_AFTER_MS;\n  return {\n    skill: eligible && (suggestion.skill_score || 0) >= SOFT_MIN,\n    agent: eligible && (suggestion.agent_score || 0) >= SOFT_MIN,\n  };\n}\n\n// ============================================================\n// P6 — detectTech + npx-find (default OFF, injected spawn)\n// ============================================================\n\n// Ported verbatim from `~/.claude/hooks/skill-router.sh` (L71-124, ~50 entries).\n// NOTE: bash associative-array iteration order is undefined/hash-based, so this\n// port (a JS `Map`, which IS insertion-ordered) makes a previously non-deterministic\n// behaviour deterministic — an intentional, spec-compatible design decision, not a\n// regression.\nexport const TECH_KEYWORDS = new Map([\n  [\"laravel\", \"laravel\"],\n  [\"symfony\", \"symfony\"],\n  [\"react\", \"react\"],\n  [\"nextjs\", \"next.js\"],\n  [\"next.js\", \"next.js\"],\n  [\"vue\", \"vue\"],\n  [\"nuxt\", \"nuxt\"],\n  [\"svelte\", \"svelte\"],\n  [\"angular\", \"angular\"],\n  [\"django\", \"django\"],\n  [\"flask\", \"flask\"],\n  [\"fastapi\", \"fastapi\"],\n  [\"rails\", \"rails\"],\n  [\"ruby on rails\", \"rails\"],\n  [\"spring\", \"spring\"],\n  [\"express\", \"express\"],\n  [\"nestjs\", \"nestjs\"],\n  [\"expo\", \"expo\"],\n  [\"react native\", \"react native\"],\n  [\"flutter\", \"flutter\"],\n  [\"swift\", \"swift\"],\n  [\"swiftui\", \"swiftui\"],\n  [\"kotlin\", \"kotlin\"],\n  [\"solidity\", \"solidity\"],\n  [\"rust\", \"rust\"],\n  [\"golang\", \"golang\"],\n  [\"go\", \"golang\"],\n  [\"unity\", \"unity\"],\n  [\"unreal\", \"unreal\"],\n  [\"godot\", \"godot\"],\n  [\"wordpress\", \"wordpress\"],\n  [\"drupal\", \"drupal\"],\n  [\"medusa\", \"medusa\"],\n  [\"shopify\", \"shopify\"],\n  [\"stripe\", \"stripe\"],\n  [\"supabase\", \"supabase\"],\n  [\"firebase\", \"firebase\"],\n  [\"prisma\", \"prisma\"],\n  [\"tailwind\", \"tailwind\"],\n  [\"nativewind\", \"nativewind\"],\n  [\"remotion\", \"remotion\"],\n  [\"playwright\", \"playwright\"],\n  [\"cypress\", \"cypress\"],\n  [\"jest\", \"jest\"],\n  [\"pytest\", \"pytest\"],\n  [\"docker\", \"docker\"],\n  [\"kubernetes\", \"kubernetes\"],\n  [\"terraform\", \"terraform\"],\n  [\"vercel\", \"vercel\"],\n  [\"netlify\", \"netlify\"],\n  [\"aws\", \"aws\"],\n  [\"gcp\", \"gcp\"],\n]);\n\n/** First-match-wins (insertion order) tech-keyword detector. \"\" when none match. */\nexport function detectTech(promptLower) {\n  const lower = (promptLower || \"\").toLowerCase();\n  for (const [keyword, tech] of TECH_KEYWORDS) {\n    if (lower.includes(keyword)) return tech;\n  }\n  return \"\";\n}\n\nconst NPX_CACHE_TTL_MS = 60 * 60 * 1000; // 1h\nconst NPX_TIMEOUT_MS = 5000; // 5s\n\n// W2: glyphs used by the `npx skills find` ASCII banner — stripped like the bash\n// pipeline's `grep -v '█\\|╔\\|╗\\|╚\\|╝\\|║\\|═'`.\nconst NPX_BANNER_RE = /[█╔╗╚╝║═]/;\n// eslint-disable-next-line no-control-regex -- intentional: strips ANSI SGR sequences.\nconst ANSI_RE = /\\x1b\\[[0-9;]*m/g;\n\n/**\n * W2: sanitize raw `npx skills find` stdout before it EVER reaches the cache or the\n * model's context — mirrors the bash source's own pipeline exactly: cap the SOURCE at\n * 2500 chars, strip ANSI color codes, keep at most 20 lines, drop the ASCII banner +\n * blank lines, then cap at 15 lines. Untreated, this was (a) unbounded context bloat and\n * (b) a prompt-injection surface: arbitrary text from an external registry entering the\n * model's context looking like an instruction, not quoted data.\n */\nexport function sanitizeNpxOutput(raw) {\n  const capped = (raw || \"\").slice(0, 2500);\n  const noAnsi = capped.replace(ANSI_RE, \"\");\n  const first20 = noAnsi.split(\"\\n\").slice(0, 20);\n  const noBannerNoBlank = first20.filter((l) => l.trim() !== \"\" && !NPX_BANNER_RE.test(l));\n  return noBannerNoBlank.slice(0, 15).join(\"\\n\");\n}\n\n/**\n * `npx skills find <tech>` — OFF by default, opt-in via `SKILLFORGE_NPX_FIND=1`.\n * Cache key = `sha256(tech)` (node:crypto, not the bash source's `md5sum`) under\n * `npxCacheDir`, 1h TTL via the injected clock.\n *\n * K2: `deps.spawn` is (and always was) `spawnSync`-shaped — a SYNCHRONOUS call that\n * blocks the event loop. `spawnSync` silently IGNORES an `AbortSignal`-shaped `signal`\n * option (only the async `spawn`/`exec` APIs honour it), and a `setTimeout` scheduled to\n * fire the abort NEVER RUNS because the event loop is blocked by the synchronous call\n * itself. A cold `npx --yes skills find <tech>` (package download) would therefore hang\n * the `UserPromptSubmit` hook indefinitely — verified empirically: `spawnSync('sleep',\n * ['2'], {signal: <aborted after 300ms>})` still takes ~2000ms and exits status 0. Fixed\n * by using `spawnSync`'s OWN `timeout`/`killSignal` options, which the underlying syscall\n * actually enforces — the bash source had the equivalent `timeout 10 npx ...`.\n *\n * Fail-open on any throw (timeout, missing binary, etc.) -> `\"\"`, never hangs or crashes\n * the prompt.\n */\nexport function npxFind(tech, deps) {\n  if (deps.env.SKILLFORGE_NPX_FIND !== \"1\") return \"\";\n\n  const cacheDir = npxCacheDirOf(deps);\n  const key = createHash(\"sha256\").update(tech).digest(\"hex\");\n  const cacheFile = deps.path.join(cacheDir, key);\n\n  let cacheStat = null;\n  try {\n    cacheStat = deps.fs.statSync(cacheFile);\n  } catch {\n    cacheStat = null;\n  }\n  if (cacheStat && deps.now() - cacheStat.mtimeMs < NPX_CACHE_TTL_MS) {\n    try {\n      return deps.fs.readFileSync(cacheFile, \"utf8\");\n    } catch {\n      // fall through and re-fetch on an unreadable cache entry\n    }\n  }\n\n  let result;\n  try {\n    result = deps.spawn(\"npx\", [\"--yes\", \"skills\", \"find\", tech], {\n      timeout: NPX_TIMEOUT_MS,\n      killSignal: \"SIGKILL\",\n      encoding: \"utf8\",\n    });\n  } catch {\n    return \"\"; // fail-open: timeout kill/throw -> \"tech detected, no results\" branch\n  }\n\n  // F2: `spawnSync` does NOT throw when the binary itself is missing — it returns\n  // `{error: Error{code:'ENOENT'}, status: null, stdout: null}`. Left unhandled, that fell\n  // through to the SAME \"\" return as a genuine `{error: undefined, status: 0, stdout: \"\"}`\n  // (\"npx ran fine, found nothing\") — byte-identical, with no signal at all, unlike every\n  // other degraded path in this function (timeout, non-zero status: both fail open to \"\"\n  // too, but this is the one case where the failure mode itself — \"npx isn't even on\n  // PATH\" — is worth a distinct, loud diagnostic). Never cached either way.\n  if (result && result.error && result.error.code === \"ENOENT\") {\n    deps.warn(\"npx not found on PATH — skill discovery unavailable\");\n    return \"\";\n  }\n\n  // W2: `spawnSync` does NOT throw on timeout/failure — it returns `{error, status, stdout}`\n  // with a possibly non-empty PARTIAL stdout (a killed process's buffered output so far).\n  // Pre-fix, only `result.stdout` truthiness was checked, so a timed-out or failed `npx`\n  // yielded partial garbage that got sanitized, CACHED for 1h, and injected into the\n  // model's context inside the EXTERNAL DATA fence as if it were a genuine result.\n  if (result && (result.error || (typeof result.status === \"number\" && result.status !== 0))) {\n    return \"\";\n  }\n\n  const raw = (result && result.stdout) || \"\";\n  if (!raw) return \"\";\n  const clean = sanitizeNpxOutput(raw);\n  if (!clean) return \"\";\n\n  ensureDirSafe(deps, cacheDir);\n  try {\n    deps.fs.writeFileSync(cacheFile, clean);\n  } catch {\n    // caching is best-effort; not fatal\n  }\n  return clean;\n}\n"

export const LEXICON_MJS = "/**\n * Spanish -> English term lexicon for the router.\n *\n * The router scores the user's prompt against skill descriptions, and those descriptions\n * are written in English. A Spanish prompt therefore shares almost no tokens with them,\n * so noise outranks the right answer. Measured against the real 1307-skill index, five\n * out of five Spanish prompts routed to something unrelated (\"revisar la seguridad de\n * este endpoint\" -> graphql; \"escribir la documentacion\" -> react-email).\n *\n * This is a LANGUAGE gap, not a semantics gap, so it is fixed with a lexicon rather than\n * embeddings. Embeddings would put a hard Ollama dependency plus 50-200ms on the critical\n * path of a hook that runs on every single prompt — a worse failure mode than the one it\n * would fix, and no better at the mismatch that actually causes the misses.\n *\n * Honest about the limits: this buys bilingual LEXICAL matching. It does not buy semantic\n * understanding. A prompt whose words never appear in any description still misses.\n *\n * Keys are accent-stripped and lowercase; `expandQuery` normalizes before lookup, and also\n * retries a naive singular form, so \"animaciones\" and \"animación\" both reach \"animation\".\n */\nexport const ES_EN = {\n  // UI / frontend\n  animacion: [\"animation\", \"motion\"],\n  animar: [\"animate\", \"animation\"],\n  transicion: [\"transition\"],\n  desplazamiento: [\"scroll\"],\n  boton: [\"button\"],\n  pantalla: [\"screen\"],\n  ventana: [\"modal\", \"dialog\"],\n  cajon: [\"drawer\"],\n  formulario: [\"form\"],\n  componente: [\"component\"],\n  diseno: [\"design\", \"ui\"],\n  maquetado: [\"layout\"],\n  estilo: [\"style\", \"css\"],\n  tipografia: [\"typography\", \"font\"],\n  pulido: [\"polish\", \"craft\"],\n  acabado: [\"polish\"],\n  interfaz: [\"interface\", \"ui\"],\n  usabilidad: [\"usability\", \"ux\"],\n  accesibilidad: [\"accessibility\", \"a11y\"],\n  oscuro: [\"dark\"],\n  tema: [\"theme\"],\n  movil: [\"mobile\"],\n  escritorio: [\"desktop\"],\n  navegador: [\"browser\"],\n\n  // Backend / data\n  servidor: [\"server\", \"backend\"],\n  consulta: [\"query\"],\n  base: [\"database\"],\n  datos: [\"data\", \"database\"],\n  tabla: [\"table\"],\n  esquema: [\"schema\"],\n  migracion: [\"migration\"],\n  indice: [\"index\"],\n  cache: [\"cache\", \"caching\"],\n  cola: [\"queue\"],\n  autenticacion: [\"authentication\", \"auth\"],\n  autorizacion: [\"authorization\", \"auth\"],\n  sesion: [\"session\"],\n  contrasena: [\"password\"],\n  usuario: [\"user\"],\n  archivo: [\"file\"],\n  carpeta: [\"directory\", \"folder\"],\n  ruta: [\"route\", \"path\"],\n  peticion: [\"request\"],\n  respuesta: [\"response\"],\n  puerto: [\"port\"],\n  despliegue: [\"deploy\", \"deployment\"],\n  contenedor: [\"container\", \"docker\"],\n  entorno: [\"environment\"],\n  variable: [\"variable\", \"env\"],\n\n  // Quality / process\n  prueba: [\"test\", \"testing\"],\n  probar: [\"test\"],\n  cobertura: [\"coverage\"],\n  revisar: [\"review\"],\n  revision: [\"review\"],\n  auditar: [\"audit\"],\n  auditoria: [\"audit\"],\n  seguridad: [\"security\"],\n  vulnerabilidad: [\"vulnerability\"],\n  fuga: [\"leak\"],\n  rendimiento: [\"performance\"],\n  optimizar: [\"optimize\", \"optimization\"],\n  optimizacion: [\"optimization\", \"performance\"],\n  lento: [\"slow\", \"performance\"],\n  rapido: [\"fast\", \"performance\"],\n  memoria: [\"memory\"],\n  error: [\"error\", \"bug\"],\n  fallo: [\"failure\", \"bug\"],\n  arreglar: [\"fix\"],\n  depurar: [\"debug\"],\n  refactorizar: [\"refactor\"],\n  refactorizacion: [\"refactor\", \"refactoring\"],\n  documentacion: [\"documentation\", \"docs\"],\n  documentar: [\"document\", \"documentation\"],\n  guia: [\"guide\"],\n  registro: [\"log\", \"logging\"],\n  monitoreo: [\"monitoring\", \"observability\"],\n  desplegar: [\"deploy\"],\n\n  // Architecture / meta\n  arquitectura: [\"architecture\"],\n  patron: [\"pattern\"],\n  dependencia: [\"dependency\"],\n  biblioteca: [\"library\"],\n  libreria: [\"library\"],\n  paquete: [\"package\"],\n  version: [\"version\", \"versioning\"],\n  publicar: [\"release\", \"publish\"],\n  lanzamiento: [\"release\"],\n  rama: [\"branch\"],\n  fusionar: [\"merge\"],\n  confirmacion: [\"commit\"],\n  flujo: [\"workflow\", \"flow\"],\n  tarea: [\"task\"],\n  agente: [\"agent\"],\n  herramienta: [\"tool\"],\n  correo: [\"email\"],\n  pago: [\"payment\"],\n  tienda: [\"store\", \"ecommerce\"],\n  busqueda: [\"search\"],\n  buscar: [\"search\"],\n  imagen: [\"image\"],\n  video: [\"video\"],\n  juego: [\"game\"],\n\n  // Build / tooling\n  compilar: [\"build\", \"compile\"],\n  compilacion: [\"build\"],\n  empaquetar: [\"bundle\", \"package\"],\n  instalar: [\"install\"],\n  actualizar: [\"update\", \"upgrade\"],\n  dependencias: [\"dependency\", \"dependencies\"],\n  script: [\"script\"],\n  tuberia: [\"pipeline\"],\n  integracion: [\"integration\", \"ci\"],\n  entrega: [\"delivery\", \"deployment\"],\n\n  // Security\n  credenciales: [\"credentials\", \"secrets\"],\n  secreto: [\"secret\"],\n  clave: [\"key\", \"password\"],\n  cifrado: [\"encryption\", \"crypto\"],\n  cifrar: [\"encrypt\"],\n  permiso: [\"permission\"],\n  rol: [\"role\"],\n  ataque: [\"attack\"],\n  inyeccion: [\"injection\"],\n  amenaza: [\"threat\"],\n  riesgo: [\"risk\"],\n  cumplimiento: [\"compliance\"],\n\n  // Frontend, deeper — most users of this tool write Spanish and build UIs\n  maqueta: [\"mockup\", \"layout\"],\n  rejilla: [\"grid\"],\n  espaciado: [\"spacing\"],\n  color: [\"color\", \"palette\"],\n  paleta: [\"palette\", \"color\"],\n  sombra: [\"shadow\"],\n  borde: [\"border\"],\n  icono: [\"icon\"],\n  fuente: [\"font\", \"typography\"],\n  responsivo: [\"responsive\"],\n  adaptable: [\"responsive\"],\n  carrusel: [\"carousel\"],\n  pestana: [\"tab\"],\n  menu: [\"menu\", \"navigation\"],\n  navegacion: [\"navigation\"],\n  encabezado: [\"header\"],\n  pie: [\"footer\"],\n  barra: [\"bar\", \"sidebar\"],\n  tarjeta: [\"card\"],\n  lista: [\"list\"],\n  emergente: [\"popover\", \"modal\"],\n  notificacion: [\"toast\", \"notification\"],\n  cargando: [\"loading\", \"skeleton\"],\n  arrastrar: [\"drag\"],\n  deslizar: [\"swipe\"],\n  gesto: [\"gesture\"],\n  microinteraccion: [\"microinteraction\", \"interaction\"],\n  microinteracciones: [\"microinteraction\", \"interaction\"],\n  plano: [\"flat\", \"polish\"],\n  soso: [\"bland\", \"polish\"],\n  bonito: [\"beautiful\", \"design\"],\n  elegante: [\"elegant\", \"polish\"],\n\n  // Business / product\n  carrito: [\"cart\", \"checkout\"],\n  compra: [\"purchase\", \"checkout\"],\n  factura: [\"invoice\", \"billing\"],\n  suscripcion: [\"subscription\", \"billing\"],\n  cliente: [\"customer\", \"client\"],\n  reunion: [\"meeting\", \"calendar\"],\n  calendario: [\"calendar\"],\n  informe: [\"report\", \"reporting\"],\n  reporte: [\"report\"],\n  panel: [\"dashboard\"],\n  tablero: [\"dashboard\", \"board\"],\n  grafico: [\"chart\", \"graph\"],\n  metrica: [\"metric\", \"analytics\"],\n  analitica: [\"analytics\"],\n  embudo: [\"funnel\"],\n  campana: [\"campaign\"],\n  mercado: [\"market\", \"marketing\"],\n  ventas: [\"sales\"],\n  empleo: [\"job\"],\n  hoja: [\"sheet\", \"resume\"],\n}\n\n/** Strip accents and lowercase, so \"animación\" and \"animacion\" hit the same key. */\nexport function normalizeEs(word) {\n  return word\n    .toLowerCase()\n    .normalize(\"NFD\")\n    .replace(/[̀-ͯ]/g, \"\")\n}\n\n/**\n * A naive Spanish singularizer. Only used as a LOOKUP fallback — it never rewrites the\n * user's token, so a wrong guess costs nothing but a missed lookup.\n */\nexport function singularizeEs(word) {\n  if (word.length <= 3) return word\n  if (word.endsWith(\"ces\")) return word.slice(0, -3) + \"z\" // luces -> luz\n  if (word.endsWith(\"es\")) return word.slice(0, -2) // errores -> error\n  if (word.endsWith(\"s\")) return word.slice(0, -1) // pruebas -> prueba\n  return word\n}\n"

export const GATE_LIB_MJS = "/**\n * skill-gate-lib.mjs — THIN ADAPTER over `../core/router-core.mjs`.\n *\n * This file used to carry its OWN hand-written copy of the scorer (STOPWORDS,\n * AMBIENT, tokenize, scoreSkills, classify, loadIndex). That copy was one of the\n * two twins that DRIFTED (the other lived in the opencode plugin) — the whole\n * point of `gate/core/router-core.mjs` is that there is now exactly ONE scorer.\n * Everything scoring-related below is a re-export or a 3-line wrapper; nothing is\n * re-implemented here.\n *\n * What DOES legitimately live here (Claude-gate-specific, not scoring):\n *   - the real-fs `DEPS` adapter (router-core is hermetic: every function takes\n *     `deps` explicitly, and this is one of the few allowed places to bind the\n *     real fs/env/home/cwd/clock),\n *   - the `~/.claude/.skillgate/` per-session contract paths,\n *   - `readSkillBody` (SKILL.md lookup — a gate-only concern),\n *   - `ensureGateIndex()` — builds the on-disk index BEFORE any scoring happens,\n *     so turn 1 on a fresh install is never a silent no-op.\n *\n * Consumers: skill-gate-eval.mjs (UserPromptSubmit), skill-gate-track.mjs\n * (PostToolUse:Skill), skill-gate-stop.mjs (Stop).\n *\n * Pure Node ESM, no deps, cross-platform.\n */\n\nimport {\n  defaultDeps,\n  ensureIndex,\n  loadIndex as coreLoadIndex,\n  scoreGate,\n  skillsIndexPath as coreSkillsIndexPath,\n  classify,\n  STRONG,\n  SOFT_MIN,\n} from \"../core/router-core.mjs\";\n\n/**\n * The real-fs/env/home adapter. Module-scope on purpose: these three hooks are\n * process-per-turn entrypoints, so binding once at import time is correct and keeps\n * every call site below free of `deps` plumbing. `router-core.mjs` itself NEVER\n * touches the real bindings — `defaultDeps()` is the single place they are read.\n */\nconst DEPS = defaultDeps();\n\nexport { classify, STRONG, SOFT_MIN };\n\nexport const INDEX_PATH = coreSkillsIndexPath(DEPS);\nexport const GATE_DIR = DEPS.path.join(DEPS.home, \".claude\", \".skillgate\");\n\n// Directories where a skill's SKILL.md may live (first hit wins).\nconst SKILL_DIRS = [\n  DEPS.path.join(DEPS.home, \".claude\", \"skills\"),\n  DEPS.path.join(DEPS.home, \".agents\", \"skills\"),\n  DEPS.path.join(DEPS.home, \".config\", \"opencode\", \"skills\"),\n];\n\nexport function ensureGateDir() {\n  try {\n    if (!DEPS.fs.existsSync(GATE_DIR)) DEPS.fs.mkdirSync(GATE_DIR, { recursive: true });\n  } catch {\n    // fail-open: the caller's own write will surface the real error loudly.\n  }\n  return GATE_DIR;\n}\n\nexport function gatePaths(sessionId) {\n  const sid = (sessionId || \"default\").replace(/[^A-Za-z0-9_-]/g, \"_\");\n  ensureGateDir();\n  return {\n    required: DEPS.path.join(GATE_DIR, `${sid}.required.json`),\n    activated: DEPS.path.join(GATE_DIR, `${sid}.activated`),\n    blocks: DEPS.path.join(GATE_DIR, `${sid}.blocks`),\n  };\n}\n\n/**\n * K4b: build (or refresh) the skill/agent index BEFORE anything scores against it.\n * Without this, turn 1 on a fresh install scores against a file nobody wrote yet ->\n * `[]` -> the gate silently evaluates nothing at all, self-healing only from turn 2.\n * Returns router-core's `ensureIndex` report ({skills, agents, empty, indexError, ...}).\n */\nexport function ensureGateIndex() {\n  return ensureIndex(DEPS);\n}\n\n/** Load the skill index as [{name, desc}]. Returns [] if missing/unreadable. */\nexport function loadIndex(indexPath = INDEX_PATH) {\n  return coreLoadIndex(indexPath, DEPS);\n}\n\n/**\n * Score `prompt` against the index. Thin wrapper: the scoring math itself is\n * `scoreGate` in router-core — the SINGLE source of truth both harnesses share.\n */\nexport function scoreSkills(prompt, { max = 12, indexPath = INDEX_PATH } = {}) {\n  return scoreGate(prompt, loadIndex(indexPath), { max });\n}\n\n/** Find and read a skill's SKILL.md body (truncated). \"\" if not found. */\nexport function readSkillBody(name, maxChars = 2500) {\n  for (const dir of SKILL_DIRS) {\n    const p = DEPS.path.join(dir, name, \"SKILL.md\");\n    try {\n      if (DEPS.fs.existsSync(p)) {\n        const body = DEPS.fs.readFileSync(p, \"utf8\").trim();\n        return body.length > maxChars ? body.slice(0, maxChars) + \"\\n…[truncated]\" : body;\n      }\n    } catch {\n      // unreadable — try the next dir\n    }\n  }\n  return \"\";\n}\n"

export const GATE_EVAL_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-eval.mjs — Claude Code UserPromptSubmit hook.\n *\n * Piece 1 (deterministic contract): scores the prompt, picks the top-K skills,\n * and writes them to the per-session required-set that the Stop gate enforces.\n * Piece 3 (aggressive auto-inject): inlines the top-2 SKILL.md bodies directly\n * into context so the knowledge is present even before any Skill() call.\n *\n * NEVER SILENT (the whole point of this change):\n *   - K4b: the index is BUILT here, before scoring — turn 1 on a fresh install\n *     evaluates real skills instead of scoring against a file nobody wrote yet.\n *   - W6: if that build throws, the thrown message is CAPTURED and surfaced as a\n *     [GATE WARNING]; it is never nulled into \"no info, no warning\".\n *   - W7: each of the 3 contract writes is guarded — a write failure degrades to a\n *     loud [GATE WARNING] instead of killing the hook mid-way with no output.\n *\n * stdout is injected into the model context as a <system-reminder>. stderr stays\n * empty on the happy path (the harness treats hook stderr as noise).\n */\n\nimport { writeFileSync } from \"node:fs\";\nimport { scoreSkills, classify, readSkillBody, gatePaths, ensureGateIndex } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    // If nothing is piped, don't hang.\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nconst DIRECTIVE = `INSTRUCTION: MANDATORY SKILL EVALUATION (a Stop gate enforces the required set)\n\nBefore responding, activate every skill that genuinely helps THIS task. There is\nNO limit — if several skills complement each other, activate ALL of them, not a\ntoken few. Activate via Skill() BEFORE writing code or answering. Naming a skill\nwithout calling Skill() is worthless.`;\n\nconst raw = await readStdin();\nlet prompt = \"\";\nlet sessionId = \"default\";\ntry {\n  const j = JSON.parse(raw);\n  prompt = j.prompt || j.user_prompt || \"\";\n  sessionId = j.session_id || \"default\";\n} catch {\n  prompt = raw; // fallback: raw text\n}\n\n// K4b/W6: build the index FIRST. A throw here must never be swallowed into `null` —\n// that would disable the very warning this block exists to emit.\nlet indexInfo = null;\nlet indexBuildError = null;\ntry {\n  indexInfo = ensureGateIndex();\n} catch (e) {\n  indexBuildError = e?.message ?? String(e);\n}\n\nconst warnings = [];\nif (indexBuildError) {\n  warnings.push(`[GATE WARNING] index build failed: ${indexBuildError} — skill enforcement is INACTIVE this turn.`);\n} else if (indexInfo && indexInfo.indexError) {\n  warnings.push(`[GATE WARNING] index build failed: ${indexInfo.indexError} — skill enforcement is INACTIVE this turn.`);\n} else if (indexInfo && indexInfo.empty) {\n  warnings.push(\n    \"[GATE WARNING] the skill index is EMPTY — no skills installed, so enforcement is INACTIVE. \" +\n      \"Run `router-skills` (or `npx skills add <owner/repo@skill>`) to install some.\",\n  );\n}\n\nconst scored = scoreSkills(prompt);\nconst { required, suggested } = classify(scored);\nconst p = gatePaths(sessionId);\n\n// W7: the contract writes (HARD set + per-turn trackers) are GUARDED. Unguarded, an\n// EISDIR/EACCES/ENOSPC here killed the hook before a single byte of the directive (or\n// of the warning above) was printed — a hard crash instead of a visible degradation.\nconst writeContract = (file, data) => {\n  try {\n    writeFileSync(file, data);\n    return null;\n  } catch (e) {\n    return e?.message ?? String(e);\n  }\n};\n// Each write is attempted independently (one failing path must not skip the other two),\n// and the FIRST error is what gets reported.\nconst contractErrors = [\n  writeContract(p.required, JSON.stringify({ required, ts: Date.now() })),\n  writeContract(p.activated, \"\"),\n  writeContract(p.blocks, \"0\"),\n].filter(Boolean);\nif (contractErrors.length > 0) {\n  warnings.push(`[GATE WARNING] contract not written (${contractErrors[0]}) — enforcement INACTIVE this turn.`);\n}\n\n// Always emit the directive so non-matching turns still get the discipline nudge.\nlet out = DIRECTIVE;\n\nif (warnings.length > 0) out += `\\n\\n${warnings.join(\"\\n\")}`;\n\nif (required.length > 0) {\n  out += `\\n\\nREQUIRED_SKILLS (strong match — the Stop gate BLOCKS turn-end until every one is loaded via Skill()):\\n  ${required.join(\", \")}`;\n}\nif (suggested.length > 0) {\n  out += `\\n\\nSUGGESTED_SKILLS (complementary — NOT enforced, but activate every one that genuinely helps; combining several is expected):\\n  ${suggested.join(\", \")}`;\n}\n\nif (required.length > 0 || suggested.length > 0) {\n  // Aggressive auto-inject: inline up to 2 bodies (required first) as a floor.\n  const order = [...required, ...suggested];\n  const injected = [];\n  for (const name of order.slice(0, 2)) {\n    const body = readSkillBody(name);\n    if (body) injected.push(`\\n----- AUTO-INJECTED SKILL: ${name} -----\\n${body}`);\n  }\n  if (injected.length > 0) {\n    out += `\\n\\nThese skill bodies are pre-loaded for you (still call Skill() on them so the harness registers them + runs any tooling):\\n${injected.join(\"\\n\")}`;\n  }\n}\n\nprocess.stdout.write(out + \"\\n\");\n"

export const GATE_TRACK_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-track.mjs — Claude Code PostToolUse hook (matcher: Skill).\n *\n * Records every Skill() activation into the per-session activated file so the\n * Stop gate can diff required vs activated. Never blocks — pure bookkeeping.\n *\n * W9: the JSON.parse and the appendFileSync have SEPARATE catches. One blind catch\n * around both meant a failed append (EISDIR/EACCES/ENOSPC) was indistinguishable\n * from malformed stdin — and a silently-dropped activation makes the Stop gate later\n * accuse the model of never loading a skill it genuinely DID load. A malformed stdin\n * payload stays silent (nothing was ever going to be recorded, so there is nothing to\n * diagnose); a WRITE failure is loud on stderr.\n */\n\nimport { appendFileSync } from \"node:fs\";\nimport { gatePaths } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nconst raw = await readStdin();\n\nlet j = null;\ntry {\n  j = JSON.parse(raw);\n} catch {\n  // Malformed stdin: no activation was ever going to be recorded. Genuinely nothing\n  // to diagnose — stay silent (asserted by a dedicated regression test).\n  process.exit(0);\n}\n\ntry {\n  if (j?.tool_name === \"Skill\") {\n    const skill = j.tool_input?.skill || j.tool_input?.name || \"\";\n    if (skill) {\n      const p = gatePaths(j.session_id || \"default\");\n      appendFileSync(p.activated, String(skill).trim() + \"\\n\");\n    }\n  }\n} catch (e) {\n  // A dropped activation is NOT harmless: the Stop gate will block the turn and tell the\n  // model it never loaded a skill it actually did. Never fail silently here.\n  try {\n    process.stderr.write(`[GATE WARNING] could not record skill activation: ${e?.message ?? String(e)}\\n`);\n  } catch {\n    // stderr itself unwritable — nothing more we can do, and we must not throw\n  }\n}\n\nprocess.exit(0);\n"

export const GATE_STOP_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-stop.mjs — Claude Code Stop hook (THE gate).\n *\n * Diffs the deterministic required-set against the skills actually activated\n * this turn. If any are missing it BLOCKS turn-end and tells the model exactly\n * which Skill() calls to make. This is what turns advisory text into a real\n * enforcement loop.\n *\n * Loop safety: enforces at most ONE block per turn. `stop_hook_active` (set by\n * Claude Code when the model resumed *because* of this hook) short-circuits to\n * allow the turn to end, so we never deadlock.\n *\n * W8: the required-set is SHAPE-VALIDATED, not merely JSON-parsed. A corrupt\n * contract like `{\"required\":\"foo\"}` parses fine, so a blind `try{JSON.parse}` never\n * fires — and `\"foo\".filter(...)` then throws an UNCAUGHT TypeError that kills the\n * Stop hook. A wrong-shaped set is now a DIAGNOSED allow (stderr diagnostic + the\n * turn proceeds), never a crash and never a silent one either.\n */\n\nimport { readFileSync, existsSync, writeFileSync } from \"node:fs\";\nimport { gatePaths } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nfunction allow() {\n  process.exit(0);\n}\n\n/** Loud, non-blocking diagnostic. stdout is the harness's control channel — never touch it here. */\nfunction warn(msg) {\n  try {\n    process.stderr.write(`[GATE WARNING] ${msg}\\n`);\n  } catch {\n    // stderr itself unwritable — nothing more we can do, and we must not throw\n  }\n}\n\n/** A valid required-set is an array of strings. Anything else is corrupt. */\nfunction isValidRequired(v) {\n  return Array.isArray(v) && v.every((x) => typeof x === \"string\");\n}\n\nconst raw = await readStdin();\nlet j = {};\ntry {\n  j = JSON.parse(raw);\n} catch {\n  allow();\n}\n\n// Already looped once because of us → let it stop, no deadlock.\nif (j.stop_hook_active === true) allow();\n\nconst p = gatePaths(j.session_id || \"default\");\nif (!existsSync(p.required)) allow();\n\nlet required = [];\ntry {\n  const parsed = JSON.parse(readFileSync(p.required, \"utf8\"));\n  const set = parsed?.required;\n  if (set === undefined || set === null) {\n    // No required-set recorded for this turn — a legitimate, non-corrupt state.\n    allow();\n  }\n  if (!isValidRequired(set)) {\n    warn(\n      `corrupt required-set at ${p.required} (expected an array of strings, got ${\n        Array.isArray(set) ? \"an array with non-string entries\" : typeof set\n      }) — allowing the turn, skill enforcement is INACTIVE this turn.`,\n    );\n    allow();\n  }\n  required = set;\n} catch (e) {\n  warn(`corrupt required-set at ${p.required} (${e?.message ?? String(e)}) — allowing the turn, skill enforcement is INACTIVE this turn.`);\n  allow();\n}\nif (required.length === 0) allow();\n\nconst activated = new Set(\n  (existsSync(p.activated) ? readFileSync(p.activated, \"utf8\") : \"\")\n    .split(\"\\n\")\n    .map((s) => s.trim().toLowerCase())\n    .filter(Boolean),\n);\n\nconst missing = required.filter((r) => !activated.has(r.toLowerCase()));\n\n// Hard cap: at most one block per turn, even if stop_hook_active is unset.\nlet blocks = 0;\ntry {\n  blocks = parseInt(readFileSync(p.blocks, \"utf8\"), 10) || 0;\n} catch {\n  /* default 0 */\n}\n\nif (missing.length === 0 || blocks >= 1) allow();\n\ntry {\n  writeFileSync(p.blocks, String(blocks + 1));\n} catch (e) {\n  // Can't persist the block counter → can't guarantee the one-block-per-turn cap →\n  // blocking anyway risks a deadlock loop. Degrade LOUDLY instead of silently looping.\n  warn(`could not record the block counter (${e?.message ?? String(e)}) — allowing the turn to avoid a deadlock loop.`);\n  allow();\n}\n\nprocess.stdout.write(\n  JSON.stringify({\n    decision: \"block\",\n    reason:\n      `SKILL GATE: faltan skills OBLIGATORIAS de este turno sin activar: ${missing.join(\", \")}. ` +\n      `Activá cada una AHORA con Skill(skill=\"<nombre>\") — en un solo mensaje si son varias — y después terminá. ` +\n      `No anuncies que las vas a usar: llamalas de verdad.`,\n  }),\n);\nprocess.exit(0);\n"

export const SKILL_ROUTER_MJS = "#!/usr/bin/env node\n/**\n * skill-router.mjs — Claude Code UserPromptSubmit hook (router port).\n *\n * Ports `~/.claude/hooks/skill-router.sh` (v3.2) to cross-platform Node ESM, backed\n * entirely by `gate/core/router-core.mjs` (the single source of truth for scoring,\n * indexing, and classification). Fail-open everywhere except the one spec'd loud\n * exception: an empty skill index emits `[ROUTER WARNING]` instead of silently\n * doing nothing (that silent no-op is the exact bug this whole change fixes).\n *\n * `main(stdinString, deps)` is the entrypoint tests call directly (no child process\n * is ever spawned by a test). The 3-line shim at the bottom is intentionally NOT\n * unit-tested (per design.md) — it only runs when this file is executed directly.\n *\n * stdout contract: PLAIN TEXT (never a JSON envelope) — see design.md's Hook I/O\n * contracts section for the evidence-based rationale (skill-gate-eval.mjs, the one\n * hook proven to work under this exact event in this repo, also emits plain text).\n */\n\nimport { readFileSync } from \"node:fs\";\nimport { fileURLToPath } from \"node:url\";\nimport {\n  defaultDeps, tokenize, ROUTER_STOPWORDS, detectTech, ensureIndex, loadIndex, skillsIndexPath,\n  agentsIndexPath, scoreRouter, scoreGate, classify, adjust, STRONG, SOFT_MIN, npxFind,\n  lastSuggestionPath,\n} from \"../core/router-core.mjs\";\n\n/** Accepts `{prompt}`, `{user_prompt}`, or raw non-JSON text (same fallback as gate-eval). */\nfunction parseInput(stdinString) {\n  try {\n    const j = JSON.parse(stdinString);\n    return { prompt: j.prompt || j.user_prompt || \"\", cwd: j.cwd };\n  } catch {\n    return { prompt: stdinString || \"\", cwd: undefined };\n  }\n}\n\nfunction run(stdinString, deps) {\n  const { prompt, cwd } = parseInput(stdinString);\n\n  // AC-3: length gate happens BEFORE tokenization/index touch — a genuine no-op.\n  if (!prompt || prompt.length < 10) return \"\";\n\n  // AC-3/K5: zero filtered tokens AND no detected tech -> no-op (bash's short-circuit).\n  // Tokenized with the ROUTER's own stopword list (skill-router.sh:138) — the same list\n  // `scoreRouter` uses internally — so this no-op gate agrees with the actual scoring.\n  const filtered = tokenize(prompt, ROUTER_STOPWORDS);\n  const tech = detectTech(prompt.toLowerCase());\n  if (filtered.length === 0 && !tech) return \"\";\n\n  const runDeps = cwd ? { ...deps, cwd } : deps;\n\n  // ensureIndex triggers a build/rebuild if the on-disk index is stale or missing\n  // (design.md's data flow); its `.empty` flag is the T032 loud-warning precondition.\n  const idxInfo = ensureIndex(runDeps);\n  // K3: a write failure building the index (EACCES/EROFS/ENOSPC) is just as loud as the\n  // empty-index case below — fail-open must never mean fail-silent.\n  if (idxInfo.indexError) {\n    return `[ROUTER WARNING] no se pudo escribir el índice (${idxInfo.indexError}) — el enforcement puede estar INACTIVO.\\n`;\n  }\n  // AC-6/AC-14: the ONE spec'd exception to fail-open — an empty index (the exact bug\n  // this whole change fixes) must be LOUD, never silent again.\n  if (idxInfo.empty) {\n    return \"[ROUTER WARNING] no se encontraron skills instaladas — el enforcement está INACTIVO. Corré `router-skills` o `npx skills add ...`.\\n\";\n  }\n  const skillIdx = loadIndex(skillsIndexPath(runDeps), runDeps);\n  const agentIdx = loadIndex(agentsIndexPath(runDeps), runDeps);\n\n  // Router-level scoring (skill-router.sh's exact bash math) + the ignored-skills bump.\n  // K6: bash's `rescore()` (skill-router.sh:207-208) applies `adjust()` to BOTH\n  // TOP_SKILLS and TOP_AGENTS — the port must too, or the \"3+ ignores -> escalate\" loop\n  // is dead for agents even though skill-usage-tracker.mjs keeps recording them.\n  const scoredSkills = scoreRouter(prompt, skillIdx, runDeps)\n    .map((s) => ({ name: s.name, score: adjust(s.name, s.score, runDeps) }))\n    .sort((a, b) => b.score - a.score);\n  const scoredAgents = scoreRouter(prompt, agentIdx, runDeps)\n    .map((s) => ({ name: s.name, score: adjust(s.name, s.score, runDeps) }))\n    .sort((a, b) => b.score - a.score);\n\n  const topSkill = scoredSkills[0];\n  const topAgent = scoredAgents[0];\n  // bash-exact (skill-router.sh:225,227): the HARD/SOFT threshold is an OR across BOTH\n  // MAX_SKILL_SCORE and MAX_AGENT_SCORE, not skill-score-only — a strong agent-only match\n  // (no comparable skill) must still cross HARD/SOFT on its own.\n  const skillScore = topSkill ? topSkill.score : 0;\n  const agentScore = topAgent ? topAgent.score : 0;\n  const maxScore = Math.max(skillScore, agentScore);\n\n  let level = \"NONE\";\n  if (maxScore >= STRONG) level = \"HARD\";\n  else if (maxScore >= SOFT_MIN) level = \"SOFT\";\n  else if (maxScore > 0) level = \"HINT\";\n\n  // D3 (design.md's top risk, solved): re-derive the gate's `required` set ourselves via\n  // the same pure scoreGate+classify given the same prompt+index — never read a file\n  // skill-gate-eval writes (that would be a cross-process race, not fixed here).\n  const gate = classify(scoreGate(prompt, skillIdx));\n\n  const lines = [];\n  if (gate.required.length > 0) {\n    // Suppress [BUSCAR-SKILL] and the tech override entirely — never contradict the gate.\n    if (topAgent) lines.push(`[AGENTS] ${topAgent.name}(${topAgent.score})`);\n  } else if (level === \"HARD\") {\n    // bash-exact (skill-router.sh:311-316): HARD is winner-take-all, not additive — a\n    // single if/elif picks EITHER the skill OR the agent, never both. Ties go to the\n    // skill (`>=`, matching bash's literal comparison).\n    if (topSkill && skillScore >= agentScore) {\n      lines.push(`[OBLIGATORIO] ${topSkill.name}(${topSkill.score})`);\n    } else if (topAgent) {\n      lines.push(`[OBLIGATORIO] ${topAgent.name}(${topAgent.score})`);\n    }\n  } else if (level === \"SOFT\") {\n    // bash-exact (skill-router.sh:317-326): SOFT is additive (both groups shown when\n    // present), but the [AGENTS] segment is emitted BARE — no \"[SUGERIDO]\" prefix — when\n    // no skill matched at all (bash's CTX starts empty, so the leading \"$PREFIX \" text is\n    // only ever attached to whichever segment is built FIRST, and skills are built first).\n    if (topSkill) {\n      lines.push(`[SUGERIDO] ${topSkill.name}(${topSkill.score})`);\n      if (topAgent) lines.push(`[AGENTS] ${topAgent.name}(${topAgent.score})`);\n    } else if (topAgent) {\n      lines.push(`[AGENTS] ${topAgent.name}(${topAgent.score})`);\n    }\n  } else {\n    // HINT (and NONE) intentionally collapse into the same fallback — a preserved bash\n    // quirk (spec's Open questions), not a bug to \"fix\".\n    let msg = \"[BUSCAR-SKILL] Sin match fuerte.\";\n    if (tech) {\n      msg += ` Tech detectada: ${tech}.`;\n      const npx = npxFind(tech, runDeps);\n      // W2: framed as QUOTED, untrusted DATA — never concatenated in as if it were part\n      // of the instruction stream. `npxFind` already caps/strips/de-banners the text\n      // (sanitizeNpxOutput); this fencing is the second, independent layer: even\n      // sanitized text from an external registry must never read as a directive.\n      if (npx) {\n        msg += `\\n----- BEGIN EXTERNAL DATA (npx skills find ${tech}; untrusted, read-only) -----\\n${npx}\\n----- END EXTERNAL DATA -----`;\n      }\n    }\n    msg += \" Considera `npx skills find <tema>` o buscar manualmente.\";\n    lines.push(msg);\n    if (topAgent) lines.push(`[AGENTS] ${topAgent.name}(${topAgent.score})`);\n  }\n\n  // AC-10 (writer half): record the suggestion for skill-usage-tracker.mjs, whenever\n  // a top skill or top agent exists — independent of whether the visible text above\n  // was suppressed by the D3 gate contract (the tracker still needs to know what was\n  // suggested, even when the router chose not to print it).\n  // W10: a write failure here used to be swallowed \"best-effort\" with zero signal —\n  // skill-usage-tracker.mjs then has nothing to read and use/ignore tracking goes dead\n  // permanently while this router's own output looks perfectly healthy. Now surfaced as\n  // a `[ROUTER WARNING]` appended to the visible text (never replacing it).\n  let suggestionWarning = \"\";\n  if (topSkill || topAgent) {\n    const suggestion = {\n      ts: runDeps.now(),\n      skill: topSkill ? topSkill.name : \"\",\n      agent: topAgent ? topAgent.name : \"\",\n      skill_score: topSkill ? topSkill.score : 0,\n      agent_score: topAgent ? topAgent.score : 0,\n      level,\n      prompt: prompt.slice(0, 200),\n      tech,\n    };\n    try {\n      runDeps.fs.writeFileSync(lastSuggestionPath(runDeps), JSON.stringify(suggestion));\n    } catch (e) {\n      const detail = (e && e.message) || String(e);\n      suggestionWarning = `[ROUTER WARNING] could not record the suggestion (${detail}) — use/ignore tracking is INACTIVE.`;\n    }\n  }\n\n  const body = lines.length ? lines.join(\"\\n\") + \"\\n\" : \"\";\n  return suggestionWarning ? body + suggestionWarning + \"\\n\" : body;\n}\n\nexport function main(stdinString, deps = defaultDeps()) {\n  try {\n    return run(stdinString, deps) || \"\";\n  } catch (e) {\n    // K3: fail-open must never mean fail-SILENT — an unexpected internal error (a bad\n    // `deps.path`, a truly unhandled fs edge case, etc.) still must not block or throw\n    // out of the hook, but returning a bare \"\" makes it indistinguishable from a genuine\n    // no-op. A short warning line preserves fail-open behaviour while keeping the failure\n    // visible.\n    const detail = (e && e.message) || String(e);\n    return `[ROUTER WARNING] internal error: ${detail}\\n`;\n  }\n}\n\nif (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {\n  process.stdout.write(main(readFileSync(0, \"utf8\")));\n  process.exit(0);\n}\n"

export const USAGE_TRACKER_MJS = "#!/usr/bin/env node\n/**\n * skill-usage-tracker.mjs — Claude Code PostToolUse hook (matcher: \"*\", tracker port).\n *\n * Ports `~/.claude/hooks/usage-tracker.sh` to cross-platform Node ESM. Reads\n * `last-suggestion.json` (written by skill-router.mjs) and credits or debits it\n * against `claude-tool-stats.json` / `ignored-skills.md` (both via router-core's\n * `recordUse`/`recordIgnore`), feeding `adjust()`'s \"3+ ignores -> +2\" bump.\n *\n * `main(stdinString, deps)` is the entrypoint tests call directly. The 3-line shim\n * at the bottom is intentionally NOT unit-tested (per design.md).\n *\n * Contract: stdout is ALWAYS empty, exit ALWAYS 0 — a tracker must never influence\n * the turn, so `main` swallows every internal error (fail-open, no exception).\n */\n\nimport { readFileSync } from \"node:fs\";\nimport { fileURLToPath } from \"node:url\";\nimport { defaultDeps, shouldIgnore, recordUse, recordIgnore, lastSuggestionPath } from \"../core/router-core.mjs\";\n\nconst TRACKED_TOOLS = new Set([\"Bash\", \"Edit\", \"Write\", \"Read\", \"Grep\", \"Glob\"]);\n\n/** Fail-open JSON read: malformed/missing -> null (never throws). */\nfunction readSuggestion(deps) {\n  const path = lastSuggestionPath(deps);\n  try {\n    if (!deps.fs.existsSync(path)) return null;\n    return JSON.parse(deps.fs.readFileSync(path, \"utf8\"));\n  } catch {\n    return null; // AC-14: invalid JSON treated as absent, never throws\n  }\n}\n\nfunction clearSuggestion(deps) {\n  try {\n    deps.fs.rmSync(lastSuggestionPath(deps), { force: true });\n  } catch {\n    // best-effort clear; not fatal\n  }\n}\n\n/**\n * C4: `recordUse`/`recordIgnore` never throw — they return `null` on success or an error\n * string on failure. Collect and return every non-null error from this run so `main` can\n * surface them via `deps.warn` (stdout must stay empty; this is the one side-channel a\n * PostToolUse hook has for a diagnostic that doesn't influence the turn).\n */\nfunction run(stdinString, deps) {\n  let evt;\n  try {\n    evt = JSON.parse(stdinString);\n  } catch {\n    return null; // AC-14: malformed stdin -> nothing to do\n  }\n\n  // F1: honour `evt.cwd` exactly like skill-router.mjs's `parseInput` + `runDeps = cwd ?\n  // {...deps, cwd} : deps` does. Without this, `recordUse`/`recordIgnore` write into\n  // `memoryDir(deps.home, deps.cwd, deps)` where `deps.cwd` is the hook SUBPROCESS's own\n  // `process.cwd()` in production — a different directory than the one skill-router.mjs's\n  // `adjust()` reads whenever the two diverge (multi-root workspaces, subshells,\n  // subagents, worktrees), silently decoupling the \"3+ ignores -> +2\" escalation loop.\n  const runDeps = evt.cwd ? { ...deps, cwd: evt.cwd } : deps;\n\n  const suggestion = readSuggestion(runDeps);\n  if (!suggestion) return null; // AC-10: no suggestion on disk -> exit immediately, write nothing\n\n  const toolName = evt.tool_name || \"\";\n  const toolInput = evt.tool_input || {};\n\n  // \"Used\" path: Skill tool matching the suggested skill, or Task/Agent tool matching\n  // the suggested subagent_type -> credit, clear, never record an ignore even if\n  // 30s+ already elapsed.\n  if (toolName === \"Skill\" && suggestion.skill && toolInput.skill === suggestion.skill) {\n    const err = recordUse(suggestion.skill, runDeps);\n    clearSuggestion(runDeps);\n    return err;\n  }\n  if (\n    (toolName === \"Task\" || toolName === \"Agent\") &&\n    suggestion.agent &&\n    toolInput.subagent_type === suggestion.agent\n  ) {\n    const err = recordUse(suggestion.agent, runDeps);\n    clearSuggestion(runDeps);\n    return err;\n  }\n\n  // \"Ignored\" path: >30s elapsed + tool in the tracked whitelist + score >= SOFT_MIN,\n  // independently for skill/agent (AC-10's \"can log one and not the other\").\n  if (!TRACKED_TOOLS.has(toolName)) return null;\n  const ignore = shouldIgnore(runDeps.now(), suggestion, toolName);\n  if (!ignore.skill && !ignore.agent) return null;\n\n  const snippet = suggestion.prompt || \"\";\n  const errs = [];\n  // C3: recordIgnore itself never throws now (it catches its own write failures), so\n  // clearSuggestion() below is UNCONDITIONALLY reached — the exact cascade this fixes:\n  // pre-fix, a mid-recordIgnore crash (corrupt stats file) skipped this clear entirely,\n  // leaving the same suggestion to be re-processed (and re-appended) on every subsequent\n  // tool call.\n  if (ignore.skill && suggestion.skill) errs.push(recordIgnore(suggestion.skill, suggestion.skill_score, \"skill\", snippet, runDeps));\n  if (ignore.agent && suggestion.agent) errs.push(recordIgnore(suggestion.agent, suggestion.agent_score, \"agent\", snippet, runDeps));\n  clearSuggestion(runDeps);\n  return errs.filter(Boolean).join(\"; \") || null;\n}\n\nexport function main(stdinString, deps = defaultDeps()) {\n  try {\n    const err = run(stdinString, deps);\n    if (err) deps.warn(`[TRACKER WARNING] could not persist use/ignore accounting: ${err}`);\n  } catch (e) {\n    // fail-open: a tracker must never throw or influence the turn — but fail-open is not\n    // fail-SILENT (C4): still surface it via the one side-channel available.\n    try {\n      deps.warn(`[TRACKER WARNING] internal error: ${(e && e.message) || String(e)}`);\n    } catch {\n      // deps.warn itself is broken — nothing more we can do without risking the turn\n    }\n  }\n  return \"\";\n}\n\nif (process.argv[1] && fileURLToPath(import.meta.url) === process.argv[1]) {\n  main(readFileSync(0, \"utf8\"));\n  process.stdout.write(\"\");\n  process.exit(0);\n}\n"

export const PLUGIN_TS = "/**\n * Spanish -> English term lexicon for the router.\n *\n * The router scores the user's prompt against skill descriptions, and those descriptions\n * are written in English. A Spanish prompt therefore shares almost no tokens with them,\n * so noise outranks the right answer. Measured against the real 1307-skill index, five\n * out of five Spanish prompts routed to something unrelated (\"revisar la seguridad de\n * este endpoint\" -> graphql; \"escribir la documentacion\" -> react-email).\n *\n * This is a LANGUAGE gap, not a semantics gap, so it is fixed with a lexicon rather than\n * embeddings. Embeddings would put a hard Ollama dependency plus 50-200ms on the critical\n * path of a hook that runs on every single prompt — a worse failure mode than the one it\n * would fix, and no better at the mismatch that actually causes the misses.\n *\n * Honest about the limits: this buys bilingual LEXICAL matching. It does not buy semantic\n * understanding. A prompt whose words never appear in any description still misses.\n *\n * Keys are accent-stripped and lowercase; `expandQuery` normalizes before lookup, and also\n * retries a naive singular form, so \"animaciones\" and \"animación\" both reach \"animation\".\n */\nconst ES_EN = {\n  // UI / frontend\n  animacion: [\"animation\", \"motion\"],\n  animar: [\"animate\", \"animation\"],\n  transicion: [\"transition\"],\n  desplazamiento: [\"scroll\"],\n  boton: [\"button\"],\n  pantalla: [\"screen\"],\n  ventana: [\"modal\", \"dialog\"],\n  cajon: [\"drawer\"],\n  formulario: [\"form\"],\n  componente: [\"component\"],\n  diseno: [\"design\", \"ui\"],\n  maquetado: [\"layout\"],\n  estilo: [\"style\", \"css\"],\n  tipografia: [\"typography\", \"font\"],\n  pulido: [\"polish\", \"craft\"],\n  acabado: [\"polish\"],\n  interfaz: [\"interface\", \"ui\"],\n  usabilidad: [\"usability\", \"ux\"],\n  accesibilidad: [\"accessibility\", \"a11y\"],\n  oscuro: [\"dark\"],\n  tema: [\"theme\"],\n  movil: [\"mobile\"],\n  escritorio: [\"desktop\"],\n  navegador: [\"browser\"],\n\n  // Backend / data\n  servidor: [\"server\", \"backend\"],\n  consulta: [\"query\"],\n  base: [\"database\"],\n  datos: [\"data\", \"database\"],\n  tabla: [\"table\"],\n  esquema: [\"schema\"],\n  migracion: [\"migration\"],\n  indice: [\"index\"],\n  cache: [\"cache\", \"caching\"],\n  cola: [\"queue\"],\n  autenticacion: [\"authentication\", \"auth\"],\n  autorizacion: [\"authorization\", \"auth\"],\n  sesion: [\"session\"],\n  contrasena: [\"password\"],\n  usuario: [\"user\"],\n  archivo: [\"file\"],\n  carpeta: [\"directory\", \"folder\"],\n  ruta: [\"route\", \"path\"],\n  peticion: [\"request\"],\n  respuesta: [\"response\"],\n  puerto: [\"port\"],\n  despliegue: [\"deploy\", \"deployment\"],\n  contenedor: [\"container\", \"docker\"],\n  entorno: [\"environment\"],\n  variable: [\"variable\", \"env\"],\n\n  // Quality / process\n  prueba: [\"test\", \"testing\"],\n  probar: [\"test\"],\n  cobertura: [\"coverage\"],\n  revisar: [\"review\"],\n  revision: [\"review\"],\n  auditar: [\"audit\"],\n  auditoria: [\"audit\"],\n  seguridad: [\"security\"],\n  vulnerabilidad: [\"vulnerability\"],\n  fuga: [\"leak\"],\n  rendimiento: [\"performance\"],\n  optimizar: [\"optimize\", \"optimization\"],\n  optimizacion: [\"optimization\", \"performance\"],\n  lento: [\"slow\", \"performance\"],\n  rapido: [\"fast\", \"performance\"],\n  memoria: [\"memory\"],\n  error: [\"error\", \"bug\"],\n  fallo: [\"failure\", \"bug\"],\n  arreglar: [\"fix\"],\n  depurar: [\"debug\"],\n  refactorizar: [\"refactor\"],\n  refactorizacion: [\"refactor\", \"refactoring\"],\n  documentacion: [\"documentation\", \"docs\"],\n  documentar: [\"document\", \"documentation\"],\n  guia: [\"guide\"],\n  registro: [\"log\", \"logging\"],\n  monitoreo: [\"monitoring\", \"observability\"],\n  desplegar: [\"deploy\"],\n\n  // Architecture / meta\n  arquitectura: [\"architecture\"],\n  patron: [\"pattern\"],\n  dependencia: [\"dependency\"],\n  biblioteca: [\"library\"],\n  libreria: [\"library\"],\n  paquete: [\"package\"],\n  version: [\"version\", \"versioning\"],\n  publicar: [\"release\", \"publish\"],\n  lanzamiento: [\"release\"],\n  rama: [\"branch\"],\n  fusionar: [\"merge\"],\n  confirmacion: [\"commit\"],\n  flujo: [\"workflow\", \"flow\"],\n  tarea: [\"task\"],\n  agente: [\"agent\"],\n  herramienta: [\"tool\"],\n  correo: [\"email\"],\n  pago: [\"payment\"],\n  tienda: [\"store\", \"ecommerce\"],\n  busqueda: [\"search\"],\n  buscar: [\"search\"],\n  imagen: [\"image\"],\n  video: [\"video\"],\n  juego: [\"game\"],\n\n  // Build / tooling\n  compilar: [\"build\", \"compile\"],\n  compilacion: [\"build\"],\n  empaquetar: [\"bundle\", \"package\"],\n  instalar: [\"install\"],\n  actualizar: [\"update\", \"upgrade\"],\n  dependencias: [\"dependency\", \"dependencies\"],\n  script: [\"script\"],\n  tuberia: [\"pipeline\"],\n  integracion: [\"integration\", \"ci\"],\n  entrega: [\"delivery\", \"deployment\"],\n\n  // Security\n  credenciales: [\"credentials\", \"secrets\"],\n  secreto: [\"secret\"],\n  clave: [\"key\", \"password\"],\n  cifrado: [\"encryption\", \"crypto\"],\n  cifrar: [\"encrypt\"],\n  permiso: [\"permission\"],\n  rol: [\"role\"],\n  ataque: [\"attack\"],\n  inyeccion: [\"injection\"],\n  amenaza: [\"threat\"],\n  riesgo: [\"risk\"],\n  cumplimiento: [\"compliance\"],\n\n  // Frontend, deeper — most users of this tool write Spanish and build UIs\n  maqueta: [\"mockup\", \"layout\"],\n  rejilla: [\"grid\"],\n  espaciado: [\"spacing\"],\n  color: [\"color\", \"palette\"],\n  paleta: [\"palette\", \"color\"],\n  sombra: [\"shadow\"],\n  borde: [\"border\"],\n  icono: [\"icon\"],\n  fuente: [\"font\", \"typography\"],\n  responsivo: [\"responsive\"],\n  adaptable: [\"responsive\"],\n  carrusel: [\"carousel\"],\n  pestana: [\"tab\"],\n  menu: [\"menu\", \"navigation\"],\n  navegacion: [\"navigation\"],\n  encabezado: [\"header\"],\n  pie: [\"footer\"],\n  barra: [\"bar\", \"sidebar\"],\n  tarjeta: [\"card\"],\n  lista: [\"list\"],\n  emergente: [\"popover\", \"modal\"],\n  notificacion: [\"toast\", \"notification\"],\n  cargando: [\"loading\", \"skeleton\"],\n  arrastrar: [\"drag\"],\n  deslizar: [\"swipe\"],\n  gesto: [\"gesture\"],\n  microinteraccion: [\"microinteraction\", \"interaction\"],\n  microinteracciones: [\"microinteraction\", \"interaction\"],\n  plano: [\"flat\", \"polish\"],\n  soso: [\"bland\", \"polish\"],\n  bonito: [\"beautiful\", \"design\"],\n  elegante: [\"elegant\", \"polish\"],\n\n  // Business / product\n  carrito: [\"cart\", \"checkout\"],\n  compra: [\"purchase\", \"checkout\"],\n  factura: [\"invoice\", \"billing\"],\n  suscripcion: [\"subscription\", \"billing\"],\n  cliente: [\"customer\", \"client\"],\n  reunion: [\"meeting\", \"calendar\"],\n  calendario: [\"calendar\"],\n  informe: [\"report\", \"reporting\"],\n  reporte: [\"report\"],\n  panel: [\"dashboard\"],\n  tablero: [\"dashboard\", \"board\"],\n  grafico: [\"chart\", \"graph\"],\n  metrica: [\"metric\", \"analytics\"],\n  analitica: [\"analytics\"],\n  embudo: [\"funnel\"],\n  campana: [\"campaign\"],\n  mercado: [\"market\", \"marketing\"],\n  ventas: [\"sales\"],\n  empleo: [\"job\"],\n  hoja: [\"sheet\", \"resume\"],\n}\n\n/** Strip accents and lowercase, so \"animación\" and \"animacion\" hit the same key. */\nfunction normalizeEs(word) {\n  return word\n    .toLowerCase()\n    .normalize(\"NFD\")\n    .replace(/[̀-ͯ]/g, \"\")\n}\n\n/**\n * A naive Spanish singularizer. Only used as a LOOKUP fallback — it never rewrites the\n * user's token, so a wrong guess costs nothing but a missed lookup.\n */\nfunction singularizeEs(word) {\n  if (word.length <= 3) return word\n  if (word.endsWith(\"ces\")) return word.slice(0, -3) + \"z\" // luces -> luz\n  if (word.endsWith(\"es\")) return word.slice(0, -2) // errores -> error\n  if (word.endsWith(\"s\")) return word.slice(0, -1) // pruebas -> prueba\n  return word\n}\n\n\n/**\n * router-core.mjs — single source of truth for skill/agent routing and gating.\n *\n * Ports `~/.claude/hooks/skill-router.sh` (v3.2) and `~/.claude/hooks/usage-tracker.sh`\n * into cross-platform Node ESM, and unifies them with the pre-existing\n * `gate/claude/skill-gate-lib.mjs` scorer (which drifted from a hand-copied opencode\n * twin). Every fs/env/home/cwd/spawn/clock/path dependency is injectable via `Deps` —\n * nothing in this file reads the real `process.env`, `os.homedir()`, `process.cwd()`,\n * or the real filesystem/network/clock EXCEPT inside `defaultDeps()`, which is the\n * only place those real bindings are touched.\n *\n * Pure Node ESM, no third-party deps, cross-platform (every path builder accepts an\n * injectable `PathImpl` so win32 behaviour is assertable from a posix host).\n *\n * HERMETICITY (W3): every exported function below REQUIRES `deps` explicitly — there is\n * no `deps = defaultDeps()` default anywhere except on `defaultDeps` itself. A default\n * parameter here would let any forgetful caller silently fall through to the real\n * fs/env/homedir/cwd, exactly the footgun `src/paths.ts`'s `opencodeBase` doc-comment\n * warns about. Only the two Claude-hook `main(stdinString, deps = defaultDeps())`\n * entrypoints (`gate/claude/skill-router.mjs`, `gate/claude/skill-usage-tracker.mjs`) and\n * the opencode plugin shell's top-level `defaultDeps()` call are allowed to touch the real\n * bindings — every other caller (including tests) must inject `deps` explicitly.\n *\n * DELIBERATE DEVIATION FROM BASH (W1): `skill-router.sh:281-310` checks `DETECTED_TECH`\n * FIRST and lets it override a HARD/SOFT local match unconditionally. This port instead\n * treats a strong LOCAL index match (HARD/SOFT, computed from the user's own installed\n * skills/agents) as a higher-confidence signal than a keyword-substring guess against the\n * ~50-entry `TECH_KEYWORDS` map, so the tech hint only surfaces in the fallback\n * (HINT/none) branch — see `gate/claude/skill-router.mjs`'s `run()`. Rationale: a mention\n * of \"react\" inside an otherwise strongly-matched prompt (e.g. \"please cache it correctly\n * today with react\") should not silently discard a real `[OBLIGATORIO]` match in favor of\n * a generic \"go run npx skills find\" nudge. Pinned by\n * `src/router-hookio.test.ts`'s \"a HARD local match wins over a detected-tech hint (W1)\".\n */\n\nimport * as nodeFs from \"node:fs\";\nimport { homedir as nodeHomedir } from \"node:os\";\nimport nodePath from \"node:path\";\nimport { spawnSync as nodeSpawnSync } from \"node:child_process\";\nimport { createHash } from \"node:crypto\";\n\n/**\n * Add the English terms a Spanish token stands for, so the prompt and the (English) skill\n * descriptions finally share vocabulary. Original tokens are always kept, so an English\n * prompt scores exactly as it did before — the lexicon can only add signal, never remove it.\n *\n * Unknown words pass through untouched. The router never invents a match it cannot justify\n * from the user's own words.\n */\nfunction expandQuery(tokens) {\n  const out = [];\n  const seen = new Set();\n  const push = (t) => {\n    if (t && !seen.has(t)) {\n      seen.add(t);\n      out.push(t);\n    }\n  };\n\n  for (const raw of tokens) {\n    push(raw);\n    const norm = normalizeEs(raw);\n    const hit = ES_EN[norm] || ES_EN[singularizeEs(norm)];\n    if (hit) for (const en of hit) push(en);\n  }\n  return out;\n}\n\n/**\n * @typedef {object} FsLike   subset actually used — a plain object literal satisfies it\n * @property {(p:string)=>boolean} existsSync\n * @property {(p:string,enc:string)=>string} readFileSync\n * @property {(p:string,data:string)=>void} writeFileSync\n * @property {(p:string,data:string)=>void} appendFileSync\n * @property {(p:string,o?:{recursive?:boolean})=>void} mkdirSync\n * @property {(p:string)=>string[]} readdirSync            // names only; NEVER withFileTypes\n * @property {(p:string)=>{isDirectory():boolean,isFile():boolean,mtimeMs:number,size:number}} statSync // FOLLOWS symlinks (skills are links)\n * @property {(p:string,o?:{force?:boolean})=>void} rmSync\n * @property {(from:string,to:string)=>void} renameSync     // POSIX/NTFS-atomic; used for index writes (K4a)\n *\n * @typedef {object} Deps\n * @property {FsLike} fs\n * @property {Record<string,string|undefined>} env\n * @property {string} home        // never os.homedir() inside this module\n * @property {string} cwd         // never process.cwd() inside this module\n * @property {(cmd:string,args:string[],o:object)=>{stdout:string,status:number}} spawn\n * @property {()=>number} now     // ms epoch; frozen in tests\n * @property {import(\"node:path\").PlatformPath} path\n * @property {(msg:string)=>void} warn  // C4: side-channel diagnostic (stderr in prod) for\n *   hooks whose stdout contract must stay empty/unaffected (e.g. skill-usage-tracker.mjs)\n *   — fail-open must never mean fail-SILENT just because stdout can't carry the signal.\n */\n\n/**\n * Real bindings. The ONLY place `node:fs` / `node:os` / `node:path` /\n * `node:child_process` / `node:crypto` are touched in this module.\n * Intentionally NOT unit-tested directly (calling it would read the real\n * `homedir()`, violating the hermetic-test rule) — exercised only indirectly\n * via the hook entrypoints' shims and manual smoke checks.\n * @returns {Deps}\n */\nfunction defaultDeps() {\n  return {\n    fs: {\n      existsSync: nodeFs.existsSync,\n      readFileSync: nodeFs.readFileSync,\n      writeFileSync: nodeFs.writeFileSync,\n      appendFileSync: nodeFs.appendFileSync,\n      mkdirSync: nodeFs.mkdirSync,\n      readdirSync: nodeFs.readdirSync,\n      statSync: nodeFs.statSync,\n      rmSync: nodeFs.rmSync,\n      renameSync: nodeFs.renameSync,\n    },\n    env: process.env,\n    home: nodeHomedir(),\n    cwd: process.cwd(),\n    spawn: nodeSpawnSync,\n    now: () => Date.now(),\n    path: nodePath,\n    warn: (msg) => {\n      try {\n        process.stderr.write(String(msg) + \"\\n\");\n      } catch {\n        // stderr itself unwritable — nothing more we can do, must not throw\n      }\n    },\n  };\n}\n\n// ============================================================\n// P1 — primitives: STOPWORDS / tokenize / bigrams / classify\n// ============================================================\n\n// Ported verbatim from `gate/claude/skill-gate-lib.mjs` (L28-40) — the CORRECT,\n// complete list (source of truth per AC-5). The opencode-side hand copy this\n// change deletes was missing the accented `también`, silently turning a\n// `suggested` result into `required` via the LEADER fallback.\nconst STOPWORDS = new Set([\n  // EN\n  \"the\", \"and\", \"for\", \"with\", \"that\", \"this\", \"you\", \"your\", \"are\", \"can\",\n  \"have\", \"has\", \"was\", \"will\", \"how\", \"what\", \"why\", \"when\", \"where\", \"into\",\n  \"from\", \"then\", \"than\", \"not\", \"but\", \"all\", \"any\", \"get\", \"use\", \"using\",\n  \"please\", \"make\", \"want\", \"need\", \"help\", \"let\", \"let's\", \"lets\", \"add\",\n  // ES\n  \"que\", \"los\", \"las\", \"una\", \"uno\", \"por\", \"con\", \"para\", \"como\", \"esto\",\n  \"esta\", \"este\", \"eso\", \"porque\", \"pero\", \"todo\", \"todos\", \"toda\", \"todas\",\n  \"muy\", \"mas\", \"más\", \"hacer\", \"haz\", \"hazlo\", \"quiero\", \"porfavor\", \"porfa\",\n  \"favor\", \"mira\", \"listo\", \"ahora\", \"tambien\", \"también\", \"aplica\", \"aplicas\",\n  \"sabes\", \"algo\", \"veo\", \"correcto\", \"aca\", \"acá\", \"aqui\", \"aquí\", \"utiliza\",\n]);\n\n// K5: ported VERBATIM from `skill-router.sh:138`'s own `STOPWORDS` bash string — a\n// DIFFERENT, materially smaller list than the gate's `STOPWORDS` above (e.g. it keeps\n// \"proyecto\", \"de\", \"con\", \"el\", \"puedes\", \"gracias\", \"dime\", \"create\", \"could\"/\"would\"/\n// \"should\" out of scoring, several of which the gate's list does NOT). `scoreRouter`\n// (the bash `awk` scoring formula) must tokenize with THIS list — reusing the gate's list\n// would let tokens the real bash router treats as noise leak into scoring, silently\n// diverging from `skill-router.sh`'s actual output on ordinary prompts.\nconst ROUTER_STOPWORDS = new Set([\n  \"el\", \"la\", \"los\", \"las\", \"un\", \"una\", \"de\", \"del\", \"y\", \"o\", \"que\", \"como\", \"para\",\n  \"por\", \"con\", \"sin\", \"en\", \"sobre\", \"es\", \"son\", \"este\", \"esto\", \"mi\", \"tu\", \"su\", \"se\",\n  \"lo\", \"le\", \"me\", \"te\",\n  \"the\", \"and\", \"or\", \"for\", \"with\", \"this\", \"that\", \"can\", \"could\", \"would\", \"should\",\n  \"help\", \"need\", \"want\", \"make\", \"create\", \"get\",\n  \"puedes\", \"favor\", \"please\", \"thanks\", \"gracias\", \"hacer\", \"dime\", \"voy\", \"proyecto\",\n  \"tener\", \"haria\", \"vas\", \"hago\", \"pasos\", \"primero\", \"antes\", \"empezar\",\n]);\n\n/** Lowercase, split on non-alnum (incl. Spanish diacritics), drop len<3, drop stopwords.\n * `stopwords` defaults to the GATE's list (`scoreGate`'s caller); `scoreRouter` passes\n * `ROUTER_STOPWORDS` explicitly (K5) — the two scorers intentionally use DIFFERENT\n * stopword sets, matching their respective bash sources. */\n/**\n * Two-letter tokens that are real technical signals, not noise.\n *\n * The `length >= 3` filter exists to kill \"de\", \"el\", \"un\" — and it was also killing the\n * strongest domain terms we have. Concretely: for \"necesito armar un componente de UI con\n * buen pulido\", emil-design-eng — whose description literally reads \"UI polish, component\n * design\" — scored 2 against a SOFT_MIN of 3 and was dropped. It lost by exactly the point\n * that \"ui\" would have contributed.\n */\nconst SHORT_TERMS = new Set([\"ui\", \"ux\", \"db\", \"ci\", \"cd\", \"qa\", \"ai\", \"js\", \"ts\", \"go\", \"os\", \"id\"]);\n\n/**\n * How many scored candidates reach classify().\n *\n * The bash original ended with `head -3`, and the port kept it faithfully. That cap made\n * the documented contract false: REQUIRED is capped, SUGGESTED is supposed to be uncapped\n * (\"if five skills genuinely help, all five are surfaced\"), but classify() never saw more\n * than three rows — a complementary skill ranked fourth was discarded before anyone could\n * suggest it.\n *\n * Widening the pool does NOT loosen enforcement. `required` is decided by a SCORE threshold\n * (>= STRONG), never by rank, so a wider pool can only add SUGGESTED entries. Nothing new\n * can block a turn. The cost is a handful of extra skill names in the prompt preamble.\n */\nconst CANDIDATE_POOL = 10;\n\nfunction tokenize(text, stopwords = STOPWORDS) {\n  return (text || \"\")\n    .toLowerCase()\n    .split(/[^a-z0-9áéíóúñ]+/i)\n    .filter((t) => (t.length >= 3 || SHORT_TERMS.has(t)) && !stopwords.has(t));\n}\n\n/** \"a_b\"-joined adjacent token pairs, order preserved. Pure. */\nfunction bigrams(tokens) {\n  const out = [];\n  for (let i = 0; i < tokens.length - 1; i++) {\n    out.push(`${tokens[i]}_${tokens[i + 1]}`);\n  }\n  return out;\n}\n\n// Score at/above which a match is strong enough to HARD-enforce (gate blocks).\nconst STRONG = 6;\n// Minimum score to surface at all (as a soft suggestion).\nconst SOFT_MIN = 3;\n\n/**\n * Split scored matches into the HARD-enforced `required` set and the SOFT\n * `suggested` set. Ported verbatim from `skill-gate-lib.mjs` `classify()` (L137-147).\n *   required  = score >= STRONG, capped at hardCap.\n *   LEADER=5 fallback: if nothing is \"strong\" but there's a clear dominant leader\n *   (score >= LEADER), enforce just that one.\n */\nfunction classify(scored, { hardCap = 4 } = {}) {\n  let required = scored.filter((s) => s.score >= STRONG).slice(0, hardCap).map((s) => s.name);\n  const LEADER = 5;\n  if (required.length === 0 && scored[0] && scored[0].score >= LEADER) {\n    required = [scored[0].name];\n  }\n  const suggested = scored.filter((s) => !required.includes(s.name)).map((s) => s.name);\n  return { required, suggested };\n}\n\n// ============================================================\n// P2 — scoring: scoreRouter (skill-router.sh awk math) / scoreGate (skill-gate-lib.mjs math)\n// ============================================================\n\n/**\n * EXACT bash math from `skill-router.sh`'s `score_index()` awk block (L156-181).\n * Iterates the FILTERED token array once PER OCCURRENCE (not deduplicated — a\n * token repeated 3x in the prompt contributes its per-occurrence score 3x over,\n * a verbatim bash quirk that MUST be preserved). Returns top-3, desc-sorted,\n * stable on ties (first-inserted wins).\n *\n * Per-token: desc-substring occurrence count (capped at 3) x1, plus name-substring\n * hit x3 (name compared with `-`/`_` replaced by spaces, like the bash `lname`).\n * Per-bigram (independent, additive): desc match +2, name match +2.\n */\n/**\n * Whole-word matching.\n *\n * The bash original matched with grep-style substring containment. For long English\n * tokens that is harmless; for short ones it is poison. The Spanish word \"mal\"\n * (\"bad\") — which shows up in a great many real prompts — is a substring of\n * \"deciMAL\", \"norMAL\", \"forMAL\", \"aniMAL\". Junk skills cleared the HARD threshold\n * and got injected as [OBLIGATORIO], spending context on skills unrelated to the task.\n *\n * `\\b` in JS is ASCII-only, so it would split on the accents that Spanish prompts are\n * full of (\"diseño\", \"animación\"). The boundary is expressed with lookarounds over an\n * explicit Latin-1/Latin-Extended-A word class instead.\n */\nconst WORD_CHAR = \"[A-Za-z0-9\\\\u00C0-\\\\u024F]\";\n\nfunction wordPattern(term, flags) {\n  const escaped = term.replace(/[.*+?^${}()|[\\]\\\\]/g, \"\\\\$&\");\n  return new RegExp(`(?<!${WORD_CHAR})${escaped}(?!${WORD_CHAR})`, flags);\n}\n\nfunction hasWord(haystack, term) {\n  if (!term) return false;\n  return wordPattern(term, \"\").test(haystack);\n}\n\nfunction countWord(haystack, term, cap = Infinity) {\n  if (!term) return 0;\n  const matches = haystack.match(wordPattern(term, \"g\"));\n  return matches ? Math.min(matches.length, cap) : 0;\n}\n\nfunction scoreRouter(prompt, index, _deps) {\n  // K5: tokenize with the ROUTER's own stopword list (skill-router.sh:138), NOT the\n  // gate's — see the ROUTER_STOPWORDS doc comment above.\n  // Expand Spanish terms into the English vocabulary the skill descriptions are written\n  // in. Without this the prompt and the index share no words and noise wins outright.\n  const filtered = expandQuery(tokenize(prompt, ROUTER_STOPWORDS));\n  if (filtered.length === 0) return [];\n  const bg = bigrams(filtered);\n\n  const rows = [];\n  index.forEach((row, insertionIndex) => {\n    const desc = (row.desc || \"\").toLowerCase();\n    const lname = row.name.toLowerCase().replace(/[-_]/g, \" \");\n    let score = 0;\n\n    for (const t of filtered) {\n      if (!t) continue;\n      // Whole-word, capped at 3 (the awk original capped occurrences the same way).\n      score += countWord(desc, t, 3);\n      if (hasWord(lname, t)) score += 3;\n    }\n\n    for (const pair of bg) {\n      if (!pair) continue;\n      const spaced = pair.replace(/_/g, \" \");\n      if (hasWord(desc, spaced)) score += 2;\n      if (hasWord(lname, spaced)) score += 2;\n    }\n\n    if (score > 0) rows.push({ name: row.name, score, insertionIndex });\n  });\n\n  rows.sort((a, b) => b.score - a.score || a.insertionIndex - b.insertionIndex);\n  return rows.slice(0, CANDIDATE_POOL).map((r) => ({ name: r.name, score: r.score }));\n}\n\n// Ambient/meta tokens that describe the tooling itself, not the task domain.\n// Ported verbatim from `skill-gate-lib.mjs` (L46-55).\nconst AMBIENT = new Set([\n  \"claude\", \"code\", \"opencode\", \"skill\", \"skills\", \"hook\", \"hooks\", \"gate\",\n  \"harness\", \"tool\", \"tools\", \"plugin\", \"plugins\", \"run\", \"corre\", \"corré\",\n  \"prueba\", \"pruebalo\", \"pruébalo\", \"probar\", \"test\", \"tests\", \"testing\",\n  \"instalador\", \"instaladores\", \"installer\", \"install\", \"funciona\", \"aplicar\",\n  \"aplicalo\", \"aplícalo\", \"harnes\", \"harneses\",\n  // URL / VCS chrome — a pasted link must not force domain skills.\n  \"github\", \"gitlab\", \"bitbucket\", \"com\", \"http\", \"https\", \"www\", \"git\",\n  \"repo\", \"repos\", \"link\", \"url\", \"raw\", \"main\", \"master\", \"branch\",\n]);\n\n/**\n * EXACT current gate math, moved VERBATIM from `skill-gate-lib.mjs`'s `scoreSkills()`:\n * name-token exact = 3 (0.5 if AMBIENT), name-substring = 1.5 (0 if AMBIENT),\n * desc substring = 1 (0.25 if AMBIENT). Tokens deduplicated via `Set` BEFORE scoring\n * (unlike `scoreRouter`). `opts.minScore` defaults to SOFT_MIN, matching the current\n * `scoreSkills`'s `score >= SOFT_MIN` filter (a lower `minScore` is a test-only knob\n * to inspect the raw pre-filter score).\n */\nfunction scoreGate(prompt, index, { max = 12, minScore = SOFT_MIN } = {}) {\n  const tokens = [...new Set(tokenize(prompt))];\n  if (tokens.length === 0) return [];\n\n  const scored = [];\n  for (const { name, desc } of index) {\n    const nameFlat = name.toLowerCase().replace(/[-_]/g, \"\");\n    const nameTokens = new Set(name.toLowerCase().split(/[-_]/));\n    let score = 0;\n    for (const t of tokens) {\n      const amb = AMBIENT.has(t);\n      if (nameTokens.has(t)) score += amb ? 0.5 : 3;\n      else if (nameFlat.includes(t)) score += amb ? 0 : 1.5;\n      if (desc.includes(t)) score += amb ? 0.25 : 1;\n    }\n    if (score >= minScore) scored.push({ name, desc, score });\n  }\n  scored.sort((a, b) => b.score - a.score);\n  return scored.slice(0, max);\n}\n\n// ============================================================\n// P3 — index build / load / needsRebuild / ensureIndex\n// ============================================================\n//\n// NOTE ON PATH BUILDERS: this section duplicates a small subset of the pure path\n// logic that also lives (as TypeScript) in `src/paths.ts`. That duplication is\n// intentional (see design.md): router-core.mjs must stay self-contained so it can\n// be inlined verbatim into the generated opencode plugin — it cannot import a .ts\n// file from outside the repo. Every builder here takes `deps` (home + path) rather\n// than raw `home`/`p`, matching this module's injectable-deps convention.\n\nfunction claudeDirOf(deps) {\n  return deps.path.join(deps.home, \".claude\");\n}\nfunction skillsDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \"skills\");\n}\nfunction agentsDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \"agents\");\n}\nfunction routerCacheDirOf(deps) {\n  return deps.path.join(claudeDirOf(deps), \".router-cache\");\n}\nfunction skillsIndexPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"skills-index.tsv\");\n}\nfunction agentsIndexPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"agents-index.tsv\");\n}\nfunction npxCacheDirOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"npx-cache\");\n}\nfunction lastSuggestionPathOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"last-suggestion.json\");\n}\nfunction routerStateDirOf(deps) {\n  return deps.path.join(routerCacheDirOf(deps), \"state\");\n}\n\n// Public path-builder wrappers (design.md's \"paths\" export bucket, Modules table).\n// P7 hook entrypoints (gate/claude/skill-router.mjs, skill-usage-tracker.mjs) live\n// outside this module and need these exact paths to loadIndex()/read/write the same\n// files ensureIndex()/adjust()/recordUse() already compute internally. Additive-only\n// (no existing export changed) — verified by re-running the full P0-P6 suite (78\n// pass, 0 fail) after this addition.\nfunction skillsIndexPath(deps) {\n  return skillsIndexPathOf(deps);\n}\nfunction agentsIndexPath(deps) {\n  return agentsIndexPathOf(deps);\n}\nfunction lastSuggestionPath(deps) {\n  return lastSuggestionPathOf(deps);\n}\n\n/**\n * Suggestion (QA iteration 2): fail-open (never throws), but now RETURNS the error\n * (`null` on success) instead of swallowing it — a mkdir failure here used to surface\n * only as a confusing, misattributed write error one step later.\n */\nfunction ensureDirSafe(deps, dir) {\n  try {\n    deps.fs.mkdirSync(dir, { recursive: true });\n    return null;\n  } catch (e) {\n    return (e && e.message) || String(e);\n  }\n}\n\n/**\n * Parse the `description:` frontmatter field, matching the bash `awk` extraction for the\n * common single-line case, PLUS (W6, a deliberate improvement over the bash source — the\n * bash `awk` has the exact same limitation, so this is not a regression) a YAML\n * block-scalar (`description: |`, `|-`, `|+`, `>`, `>-`, `>+`) continuation join: every\n * subsequent indented line is collected and space-joined until indentation ends. Without\n * this, a skill using this extremely common YAML style (confirmed against the real\n * installed `~/.claude/skills/academic-researcher/SKILL.md`) indexes as the literal\n * single-character description `\"|\"`, silently killing routing for it.\n */\nfunction extractDescription(content) {\n  const lines = (content || \"\").split(\"\\n\");\n  const idx = lines.findIndex((l) => /^description:/.test(l));\n  if (idx === -1) return \"\";\n  let rest = lines[idx].replace(/^description:\\s*/, \"\");\n\n  if (/^[|>][+-]?\\s*$/.test(rest.trim())) {\n    const collected = [];\n    for (let i = idx + 1; i < lines.length; i++) {\n      const line = lines[i];\n      if (line.trim() === \"\") {\n        collected.push(\"\");\n        continue;\n      }\n      if (/^\\s/.test(line)) {\n        collected.push(line.trim());\n      } else {\n        break; // indentation ended -> block scalar is done\n      }\n    }\n    rest = collected.filter(Boolean).join(\" \");\n  }\n\n  return rest.replace(/\"/g, \"\").trim().toLowerCase();\n}\n\n/**\n * K4(a): atomic index write — write to a sibling temp file, then `renameSync` it onto the\n * real path. `rename` is atomic on both POSIX and NTFS, so a reader (skill-gate-eval.mjs\n * via `ensureIndex`) can never observe a torn/partial index mid-write. Returns `null` on\n * success, or a string error message on failure (K3) — NEVER throws.\n *\n * C2: `skill-gate-eval.mjs` and `skill-router.mjs` are TWO SEPARATE PROCESSES wired on the\n * SAME UserPromptSubmit event, and Claude Code runs matching hooks in PARALLEL. A shared\n * `${path}.tmp` name meant process B's write could truncate/rewrite the tmp file process A\n * was about to `renameSync` — `rename` itself is atomic, but the SOURCE it publishes was\n * not race-free, so a torn index could still get published atomically. The tmp name is now\n * unique per call (`pid` + random), and a failed write/rename cleans up its own tmp instead\n * of leaving it orphaned.\n */\nfunction atomicWriteIndex(deps, path, data) {\n  const tmp = `${path}.${process.pid}.${Math.random().toString(36).slice(2)}.tmp`;\n  try {\n    deps.fs.writeFileSync(tmp, data);\n    deps.fs.renameSync(tmp, path);\n    return null;\n  } catch (e) {\n    try {\n      deps.fs.rmSync(tmp, { force: true });\n    } catch {\n      // best-effort cleanup; the write/rename error below is what matters\n    }\n    return (e && e.message) || String(e);\n  }\n}\n\n// Directory names pruned BEFORE recursion on the agents walk (never opened at all).\nconst PRUNED_DIR_NAMES = new Set([\"node_modules\"]);\nfunction isPrunedDirName(name) {\n  return PRUNED_DIR_NAMES.has(name) || name.startsWith(\".\");\n}\n\n/**\n * Top-level `<skillsDir>/<name>/SKILL.md` scan only (NFR: no recursion into a skill's\n * internal files). Uses `fs.statSync` (follows symlinks/junctions) — never\n * `lstat`/`dirent.isDirectory` — the exact bash bug (`find` without `-L`) this change\n * fixes. A dangling symlink (statSync throws) is skipped, not crashed. Pure computation,\n * no write — shared by `buildSkillIndex` (writes) and `needsRebuild` (W3: compares this\n * live count against what's currently indexed, to catch deletions mtime can't see).\n */\nfunction computeSkillRows(deps) {\n  const dir = skillsDirOf(deps);\n  const rows = [];\n  let names = [];\n  try {\n    names = deps.fs.readdirSync(dir);\n  } catch {\n    names = [];\n  }\n  for (const name of names) {\n    const skillPath = deps.path.join(dir, name);\n    let st;\n    try {\n      st = deps.fs.statSync(skillPath);\n    } catch {\n      continue; // dangling symlink or race — skip, don't crash\n    }\n    if (!st.isDirectory()) continue;\n    const mdPath = deps.path.join(skillPath, \"SKILL.md\");\n    let mdStat;\n    try {\n      mdStat = deps.fs.statSync(mdPath);\n    } catch {\n      continue;\n    }\n    if (!mdStat.isFile()) continue;\n    let content = \"\";\n    try {\n      content = deps.fs.readFileSync(mdPath, \"utf8\");\n    } catch {\n      continue;\n    }\n    const desc = extractDescription(content) || name;\n    rows.push({ name, desc: desc.toLowerCase() });\n  }\n  return rows;\n}\n\nfunction buildSkillIndex(deps) {\n  const rows = computeSkillRows(deps);\n  const idxPath = skillsIndexPathOf(deps);\n  // Suggestion: `ensureDirSafe` used to swallow its own mkdir error, so a subsequent\n  // unguarded write threw a misleading ENOENT that hid the REAL root cause (mkdir\n  // EACCES/EROFS). Thread the mkdir error into `writeError` first, so `indexError`\n  // reports what actually failed.\n  const mkdirError = ensureDirSafe(deps, routerCacheDirOf(deps));\n  const tsv = rows.map((r) => `${r.name}\\t${r.desc}`).join(\"\\n\") + (rows.length ? \"\\n\" : \"\");\n  const writeError = mkdirError || atomicWriteIndex(deps, idxPath, tsv);\n  return { rows: rows.length, path: idxPath, writeError };\n}\n\n/**\n * Recursive `**\\/*.md` walk of `agentsDir`, PRUNING `node_modules/` and any\n * dot-prefixed directory BEFORE recursing — those directories are never passed\n * to `readdirSync`/`statSync` at all, not merely filtered out of the result\n * (perf: the bash source's plain `find` walked `skills/playwright/node_modules`\n * — thousands of files on every prompt). Pure computation, no write — shared by\n * `buildAgentIndex` (writes) and `needsRebuild` (W3).\n */\nfunction computeAgentRows(deps) {\n  const root = agentsDirOf(deps);\n  const rows = [];\n\n  function walk(dir) {\n    let names = [];\n    try {\n      names = deps.fs.readdirSync(dir);\n    } catch {\n      return;\n    }\n    for (const name of names) {\n      if (isPrunedDirName(name)) continue; // never opened\n      const full = deps.path.join(dir, name);\n      let st;\n      try {\n        st = deps.fs.statSync(full);\n      } catch {\n        continue;\n      }\n      if (st.isDirectory()) {\n        walk(full);\n        continue;\n      }\n      if (st.isFile() && name.toLowerCase().endsWith(\".md\")) {\n        let content = \"\";\n        try {\n          content = deps.fs.readFileSync(full, \"utf8\");\n        } catch {\n          continue;\n        }\n        const base = name.replace(/\\.md$/i, \"\");\n        const desc = extractDescription(content) || base;\n        rows.push({ name: base, desc: desc.toLowerCase() });\n      }\n    }\n  }\n  walk(root);\n  return rows;\n}\n\nfunction buildAgentIndex(deps) {\n  const rows = computeAgentRows(deps);\n  const idxPath = agentsIndexPathOf(deps);\n  const mkdirError = ensureDirSafe(deps, routerCacheDirOf(deps));\n  const tsv = rows.map((r) => `${r.name}\\t${r.desc}`).join(\"\\n\") + (rows.length ? \"\\n\" : \"\");\n  const writeError = mkdirError || atomicWriteIndex(deps, idxPath, tsv);\n  return { rows: rows.length, path: idxPath, writeError };\n}\n\n/** Fail-open TSV loader: malformed lines (no tab, whitespace-only name) are skipped. */\nfunction loadIndex(idxPath, deps) {\n  let content = \"\";\n  try {\n    if (!deps.fs.existsSync(idxPath)) return [];\n    content = deps.fs.readFileSync(idxPath, \"utf8\");\n  } catch {\n    return [];\n  }\n  const rows = [];\n  for (const line of content.split(\"\\n\")) {\n    if (!line.trim()) continue;\n    const tab = line.indexOf(\"\\t\");\n    if (tab === -1) continue; // malformed: no tab character\n    const name = line.slice(0, tab).trim();\n    if (!name) continue; // whitespace-only name\n    const desc = line.slice(tab + 1).trim().toLowerCase();\n    rows.push({ name, desc });\n  }\n  return rows;\n}\n\n/** Recursive newest .md mtime under `dir`, pruning the same dirs as buildAgentIndex. */\nfunction newestMdMtime(dir, deps) {\n  let names;\n  try {\n    names = deps.fs.readdirSync(dir);\n  } catch {\n    return -1;\n  }\n  let max = -1;\n  for (const name of names) {\n    if (isPrunedDirName(name)) continue;\n    const full = deps.path.join(dir, name);\n    let st;\n    try {\n      st = deps.fs.statSync(full);\n    } catch {\n      continue;\n    }\n    if (st.isDirectory()) {\n      const sub = newestMdMtime(full, deps);\n      if (sub > max) max = sub;\n    } else if (name.toLowerCase().endsWith(\".md\")) {\n      if (st.mtimeMs > max) max = st.mtimeMs;\n    }\n  }\n  return max;\n}\n\n/**\n * `needsRebuild(srcDir, idxPath, deps, kind)` — ported from `skill-router.sh`'s\n * `needs_rebuild()`: an existing-but-empty (`0`-byte) index ALWAYS triggers a\n * rebuild attempt (`[[ ! -s \"$idx\" ]]`), regardless of mtimes; otherwise a rebuild\n * is needed iff some `.md` file under `srcDir` is newer than the index.\n *\n * W3: mtime alone is blind to DELETIONS — uninstalling a skill/agent never bumps any\n * SURVIVING file's mtime, so nothing here would ever look \"newer\" and the stale row for\n * the removed entry keeps scoring forever (`skill-gate-eval` would put a no-longer-\n * installed skill in `required`, `readSkillBody` returns \"\" silently, and the Stop gate\n * blocks the turn demanding a Skill() call that cannot succeed). Fixed by ALSO comparing\n * the currently-installed row count (`kind`: \"skill\" -> `computeSkillRows`, \"agent\" ->\n * `computeAgentRows` — the same counting logic each builder uses) against what's actually\n * on disk in the index; any mismatch (shrink OR growth the mtime check somehow missed)\n * triggers a rebuild too.\n */\nfunction needsRebuild(srcDir, idxPath, deps, kind = \"skill\") {\n  let idxStat;\n  try {\n    idxStat = deps.fs.statSync(idxPath);\n  } catch {\n    return true; // missing index -> rebuild\n  }\n  if (idxStat.size === 0) return true; // empty index -> always rebuild\n  const newest = newestMdMtime(srcDir, deps);\n  if (newest === -1) return false; // src dir missing / no md files -> nothing to rebuild from\n  if (newest > idxStat.mtimeMs) return true;\n  const currentRows = (kind === \"agent\" ? computeAgentRows(deps) : computeSkillRows(deps)).length;\n  const indexedRows = loadIndex(idxPath, deps).length;\n  return currentRows !== indexedRows;\n}\n\n/**\n * Orchestrates the skill + agent index builds: rebuilds only when `needsRebuild`\n * is true, and reports `empty:true` whenever the skills index has zero rows\n * (missing dir, zero valid `SKILL.md` entries, or all dangling symlinks) — the\n * precondition for the P7 loud empty-index warning.\n */\nfunction ensureIndex(deps) {\n  const skillsDir = skillsDirOf(deps);\n  const agentsDir = agentsDirOf(deps);\n  const skillIdxPath = skillsIndexPathOf(deps);\n  const agentIdxPath = agentsIndexPathOf(deps);\n\n  let rebuilt = false;\n  // K3: a write failure (EACCES/EROFS/ENOSPC) building either index is captured here,\n  // never thrown and never silently dropped — the caller (skill-router.mjs) turns this\n  // into a LOUD `[ROUTER WARNING]` instead of degrading to an empty, silent suggestion.\n  let indexError = null;\n\n  let skillsExists = false;\n  try {\n    skillsExists = deps.fs.statSync(skillsDir).isDirectory();\n  } catch {\n    skillsExists = false;\n  }\n  if (skillsExists && needsRebuild(skillsDir, skillIdxPath, deps, \"skill\")) {\n    const r = buildSkillIndex(deps);\n    rebuilt = true;\n    if (r.writeError) indexError = `${r.path}: ${r.writeError}`;\n  }\n\n  let agentsExists = false;\n  try {\n    agentsExists = deps.fs.statSync(agentsDir).isDirectory();\n  } catch {\n    agentsExists = false;\n  }\n  if (agentsExists && needsRebuild(agentsDir, agentIdxPath, deps, \"agent\")) {\n    const r = buildAgentIndex(deps);\n    rebuilt = true;\n    if (r.writeError && !indexError) indexError = `${r.path}: ${r.writeError}`;\n  }\n\n  const skills = loadIndex(skillIdxPath, deps);\n  const agents = loadIndex(agentIdxPath, deps);\n  // Suggestion: `empty` only ever reflected the SKILLS index — an installed-but-empty\n  // AGENTS index degraded `[AGENTS]` suggestions to permanent silence with no flag at all\n  // to detect it by. `agentsEmpty` makes that state inspectable too.\n  return {\n    skills: skills.length,\n    agents: agents.length,\n    rebuilt,\n    empty: skills.length === 0,\n    agentsEmpty: agents.length === 0,\n    indexError,\n  };\n}\n\n// ============================================================\n// P4 — memoryDir (impure wrapper; pure projectSlug/memoryDirs duplicated from\n// src/paths.ts on purpose — see the P3 path-builder note above: this module must\n// stay self-contained to be inlined into the generated opencode plugin).\n// ============================================================\n\n/** Slug = absolute cwd, every non-alnum char -> \"-\", one-for-one, no collapsing. */\nfunction projectSlugOf(cwd) {\n  return cwd.replace(/[^A-Za-z0-9]/g, \"-\");\n}\n\n/** Candidate memory dirs, most-specific first. Pure — mirrors src/paths.ts's memoryDirs. */\nfunction memoryDirsOf(deps) {\n  return [\n    deps.path.join(claudeDirOf(deps), \"projects\", projectSlugOf(deps.cwd), \"memory\"),\n    routerStateDirOf(deps),\n  ];\n}\n\n/**\n * Impure wrapper: picks the first EXISTING `memoryDirsOf` candidate, falling back\n * to the 2nd (`routerStateDir`) when the project-memory dir doesn't exist yet.\n */\nfunction memoryDir(home, cwd, deps) {\n  const d = { ...deps, home, cwd };\n  const candidates = memoryDirsOf(d);\n  for (const c of candidates) {\n    let exists = false;\n    try {\n      exists = d.fs.existsSync(c);\n    } catch {\n      exists = false;\n    }\n    if (exists) return c;\n  }\n  return candidates[candidates.length - 1];\n}\n\n// ============================================================\n// P5 — tracker accounting primitives: adjust / recordUse / recordIgnore / shouldIgnore\n// ============================================================\n\nfunction ignoredSkillsPathOf(deps) {\n  return deps.path.join(memoryDir(deps.home, deps.cwd, deps), \"ignored-skills.md\");\n}\n\n/** Fail-open JSON read: malformed/missing/unreadable -> `fallback`, never throws. */\n/**\n * C3: `JSON.parse` succeeds on `null`/`[]`/`\"x\"`/`3` — only a THROW falls back to\n * `fallback`. A truncated/corrupt state file containing e.g. `null` used to make this\n * return `null` itself, and the caller's `stats[name]` then threw a TypeError, swallowed\n * by the tracker's blind catch — worse, in `recordIgnore` the ignored-skills.md append had\n * ALREADY happened before that crash, so `clearSuggestion()` never ran and the same\n * suggestion re-appended on every subsequent tool call, cascading into a runaway HARD\n * escalation. Fixed by validating the parsed value is a genuine plain object; anything else\n * (including `null`/arrays/primitives) is treated exactly like unreadable/malformed JSON —\n * discarded, fallback returned, reported via `error` (never surfaced when the file simply\n * doesn't exist yet — that's the normal first-run case, not a corruption).\n */\nfunction readJsonSafe(deps, path, fallback) {\n  try {\n    if (!deps.fs.existsSync(path)) return { value: fallback, error: null };\n    const raw = deps.fs.readFileSync(path, \"utf8\");\n    const parsed = JSON.parse(raw);\n    if (typeof parsed !== \"object\" || parsed === null || Array.isArray(parsed)) {\n      const kind = parsed === null ? \"null\" : Array.isArray(parsed) ? \"array\" : typeof parsed;\n      return { value: fallback, error: `${path}: corrupt state (expected an object, got ${kind}) — discarded` };\n    }\n    return { value: parsed, error: null };\n  } catch (e) {\n    return { value: fallback, error: `${path}: unreadable/invalid JSON (${(e && e.message) || String(e)}) — discarded` };\n  }\n}\n\n/**\n * `adjust(name, base, deps)` — ported from `skill-router.sh`'s `adjust()`: `+2`\n * when `<memoryDir>/ignored-skills.md` has `>= 3` lines starting with\n * `\"<name> |\"`, else `+0`. Fail-open (AC-14): an unreadable/missing file defaults\n * the bump to `0`, never throws.\n */\nfunction adjust(name, base, deps) {\n  const path = ignoredSkillsPathOf(deps);\n  let content = \"\";\n  try {\n    if (!deps.fs.existsSync(path)) return base;\n    content = deps.fs.readFileSync(path, \"utf8\");\n  } catch {\n    return base; // fail-open\n  }\n  const needle = `${name} |`;\n  const count = content.split(\"\\n\").filter((line) => line.startsWith(needle)).length;\n  return count >= 3 ? base + 2 : base;\n}\n\n/** Increments `tool-stats.json[name].used` by 1 (creates the entry if absent). */\n/**\n * C4: increments `tool-stats.json[name].used`. NEVER throws — a write failure\n * (EACCES/EROFS/ENOSPC) is caught and returned as an error string (`null` on success) so\n * the caller (skill-usage-tracker.mjs's `main`) can surface a `[TRACKER WARNING]` instead\n * of letting it die inside a blind catch with zero signal.\n */\nfunction recordUse(name, deps) {\n  const memDir = memoryDir(deps.home, deps.cwd, deps);\n  const path = deps.path.join(memDir, \"claude-tool-stats.json\");\n  const { value: stats, error: readError } = readJsonSafe(deps, path, {});\n  const entry = stats[name] || { used: 0, ignored: 0 };\n  stats[name] = { ...entry, used: (entry.used || 0) + 1 };\n  ensureDirSafe(deps, memDir);\n  try {\n    deps.fs.writeFileSync(path, JSON.stringify(stats));\n    return readError;\n  } catch (e) {\n    return [readError, `${path}: ${(e && e.message) || String(e)}`].filter(Boolean).join(\"; \");\n  }\n}\n\n/**\n * Appends `\"<name> | <iso-ts> | <score> | <kind> | <snippet>\"` to\n * `ignored-skills.md` (iso-ts from `deps.now()`, never `Date.now()`), increments\n * `tool-stats.json[name].ignored`, truncates `promptSnippet` to 100 chars.\n *\n * C3/C4: NEVER throws. The append happens first (matching the original ordering — the\n * caller's `clearSuggestion()` must still run afterward regardless), and every write is\n * individually guarded so a failure anywhere in this function surfaces as a returned error\n * string instead of an uncaught exception that would leave the caller's suggestion-clear\n * step unreached.\n */\nfunction recordIgnore(name, score, kind, promptSnippet, deps) {\n  const memDir = memoryDir(deps.home, deps.cwd, deps);\n  const ignoredPath = deps.path.join(memDir, \"ignored-skills.md\");\n  const statsPath = deps.path.join(memDir, \"claude-tool-stats.json\");\n  ensureDirSafe(deps, memDir);\n\n  const iso = new Date(deps.now()).toISOString();\n  const snippet = (promptSnippet || \"\").slice(0, 100);\n  const line = `${name} | ${iso} | ${score} | ${kind} | ${snippet}\\n`;\n  let appendError = null;\n  try {\n    deps.fs.appendFileSync(ignoredPath, line);\n  } catch (e) {\n    appendError = `${ignoredPath}: ${(e && e.message) || String(e)}`;\n  }\n\n  const { value: stats, error: readError } = readJsonSafe(deps, statsPath, {});\n  const entry = stats[name] || { used: 0, ignored: 0 };\n  stats[name] = { ...entry, ignored: (entry.ignored || 0) + 1 };\n  try {\n    deps.fs.writeFileSync(statsPath, JSON.stringify(stats));\n    return [appendError, readError].filter(Boolean).join(\"; \") || null;\n  } catch (e) {\n    return [appendError, readError, `${statsPath}: ${(e && e.message) || String(e)}`].filter(Boolean).join(\"; \");\n  }\n}\n\n// Tools whose completion can count as \"ignored the suggestion\" — mirrors\n// usage-tracker.sh's `^(Bash|Edit|Write|Read|Grep|Glob)$` whitelist.\nconst IGNORE_ELIGIBLE_TOOLS = new Set([\"Bash\", \"Edit\", \"Write\", \"Read\", \"Grep\", \"Glob\"]);\nconst IGNORE_AFTER_MS = 30_000;\n\n/**\n * Pure predicate: `{skill, agent}` independently — a suggestion can log an\n * ignored skill and NOT an ignored agent, or vice versa. Requires >30s elapsed,\n * `toolName` in the tracked whitelist, and the respective score `>= SOFT_MIN`.\n */\nfunction shouldIgnore(nowMs, suggestion, toolName) {\n  // Suggestion (QA iteration 2): `nowMs - suggestion.ts` is `NaN` whenever `ts` is\n  // missing/non-numeric, and `NaN > IGNORE_AFTER_MS` is ALWAYS `false` — silently\n  // disabling ignore-tracking FOREVER for that suggestion, with zero error/warning. A\n  // missing/invalid `ts` is treated as \"old enough\" (elapsed = Infinity), not \"never old\n  // enough\".\n  const ts = suggestion && suggestion.ts;\n  const elapsed = Number.isFinite(ts) ? nowMs - ts : Infinity;\n  const eligible = IGNORE_ELIGIBLE_TOOLS.has(toolName) && elapsed > IGNORE_AFTER_MS;\n  return {\n    skill: eligible && (suggestion.skill_score || 0) >= SOFT_MIN,\n    agent: eligible && (suggestion.agent_score || 0) >= SOFT_MIN,\n  };\n}\n\n// ============================================================\n// P6 — detectTech + npx-find (default OFF, injected spawn)\n// ============================================================\n\n// Ported verbatim from `~/.claude/hooks/skill-router.sh` (L71-124, ~50 entries).\n// NOTE: bash associative-array iteration order is undefined/hash-based, so this\n// port (a JS `Map`, which IS insertion-ordered) makes a previously non-deterministic\n// behaviour deterministic — an intentional, spec-compatible design decision, not a\n// regression.\nconst TECH_KEYWORDS = new Map([\n  [\"laravel\", \"laravel\"],\n  [\"symfony\", \"symfony\"],\n  [\"react\", \"react\"],\n  [\"nextjs\", \"next.js\"],\n  [\"next.js\", \"next.js\"],\n  [\"vue\", \"vue\"],\n  [\"nuxt\", \"nuxt\"],\n  [\"svelte\", \"svelte\"],\n  [\"angular\", \"angular\"],\n  [\"django\", \"django\"],\n  [\"flask\", \"flask\"],\n  [\"fastapi\", \"fastapi\"],\n  [\"rails\", \"rails\"],\n  [\"ruby on rails\", \"rails\"],\n  [\"spring\", \"spring\"],\n  [\"express\", \"express\"],\n  [\"nestjs\", \"nestjs\"],\n  [\"expo\", \"expo\"],\n  [\"react native\", \"react native\"],\n  [\"flutter\", \"flutter\"],\n  [\"swift\", \"swift\"],\n  [\"swiftui\", \"swiftui\"],\n  [\"kotlin\", \"kotlin\"],\n  [\"solidity\", \"solidity\"],\n  [\"rust\", \"rust\"],\n  [\"golang\", \"golang\"],\n  [\"go\", \"golang\"],\n  [\"unity\", \"unity\"],\n  [\"unreal\", \"unreal\"],\n  [\"godot\", \"godot\"],\n  [\"wordpress\", \"wordpress\"],\n  [\"drupal\", \"drupal\"],\n  [\"medusa\", \"medusa\"],\n  [\"shopify\", \"shopify\"],\n  [\"stripe\", \"stripe\"],\n  [\"supabase\", \"supabase\"],\n  [\"firebase\", \"firebase\"],\n  [\"prisma\", \"prisma\"],\n  [\"tailwind\", \"tailwind\"],\n  [\"nativewind\", \"nativewind\"],\n  [\"remotion\", \"remotion\"],\n  [\"playwright\", \"playwright\"],\n  [\"cypress\", \"cypress\"],\n  [\"jest\", \"jest\"],\n  [\"pytest\", \"pytest\"],\n  [\"docker\", \"docker\"],\n  [\"kubernetes\", \"kubernetes\"],\n  [\"terraform\", \"terraform\"],\n  [\"vercel\", \"vercel\"],\n  [\"netlify\", \"netlify\"],\n  [\"aws\", \"aws\"],\n  [\"gcp\", \"gcp\"],\n]);\n\n/** First-match-wins (insertion order) tech-keyword detector. \"\" when none match. */\nfunction detectTech(promptLower) {\n  const lower = (promptLower || \"\").toLowerCase();\n  for (const [keyword, tech] of TECH_KEYWORDS) {\n    if (lower.includes(keyword)) return tech;\n  }\n  return \"\";\n}\n\nconst NPX_CACHE_TTL_MS = 60 * 60 * 1000; // 1h\nconst NPX_TIMEOUT_MS = 5000; // 5s\n\n// W2: glyphs used by the `npx skills find` ASCII banner — stripped like the bash\n// pipeline's `grep -v '█\\|╔\\|╗\\|╚\\|╝\\|║\\|═'`.\nconst NPX_BANNER_RE = /[█╔╗╚╝║═]/;\n// eslint-disable-next-line no-control-regex -- intentional: strips ANSI SGR sequences.\nconst ANSI_RE = /\\x1b\\[[0-9;]*m/g;\n\n/**\n * W2: sanitize raw `npx skills find` stdout before it EVER reaches the cache or the\n * model's context — mirrors the bash source's own pipeline exactly: cap the SOURCE at\n * 2500 chars, strip ANSI color codes, keep at most 20 lines, drop the ASCII banner +\n * blank lines, then cap at 15 lines. Untreated, this was (a) unbounded context bloat and\n * (b) a prompt-injection surface: arbitrary text from an external registry entering the\n * model's context looking like an instruction, not quoted data.\n */\nfunction sanitizeNpxOutput(raw) {\n  const capped = (raw || \"\").slice(0, 2500);\n  const noAnsi = capped.replace(ANSI_RE, \"\");\n  const first20 = noAnsi.split(\"\\n\").slice(0, 20);\n  const noBannerNoBlank = first20.filter((l) => l.trim() !== \"\" && !NPX_BANNER_RE.test(l));\n  return noBannerNoBlank.slice(0, 15).join(\"\\n\");\n}\n\n/**\n * `npx skills find <tech>` — OFF by default, opt-in via `SKILLFORGE_NPX_FIND=1`.\n * Cache key = `sha256(tech)` (node:crypto, not the bash source's `md5sum`) under\n * `npxCacheDir`, 1h TTL via the injected clock.\n *\n * K2: `deps.spawn` is (and always was) `spawnSync`-shaped — a SYNCHRONOUS call that\n * blocks the event loop. `spawnSync` silently IGNORES an `AbortSignal`-shaped `signal`\n * option (only the async `spawn`/`exec` APIs honour it), and a `setTimeout` scheduled to\n * fire the abort NEVER RUNS because the event loop is blocked by the synchronous call\n * itself. A cold `npx --yes skills find <tech>` (package download) would therefore hang\n * the `UserPromptSubmit` hook indefinitely — verified empirically: `spawnSync('sleep',\n * ['2'], {signal: <aborted after 300ms>})` still takes ~2000ms and exits status 0. Fixed\n * by using `spawnSync`'s OWN `timeout`/`killSignal` options, which the underlying syscall\n * actually enforces — the bash source had the equivalent `timeout 10 npx ...`.\n *\n * Fail-open on any throw (timeout, missing binary, etc.) -> `\"\"`, never hangs or crashes\n * the prompt.\n */\nfunction npxFind(tech, deps) {\n  if (deps.env.SKILLFORGE_NPX_FIND !== \"1\") return \"\";\n\n  const cacheDir = npxCacheDirOf(deps);\n  const key = createHash(\"sha256\").update(tech).digest(\"hex\");\n  const cacheFile = deps.path.join(cacheDir, key);\n\n  let cacheStat = null;\n  try {\n    cacheStat = deps.fs.statSync(cacheFile);\n  } catch {\n    cacheStat = null;\n  }\n  if (cacheStat && deps.now() - cacheStat.mtimeMs < NPX_CACHE_TTL_MS) {\n    try {\n      return deps.fs.readFileSync(cacheFile, \"utf8\");\n    } catch {\n      // fall through and re-fetch on an unreadable cache entry\n    }\n  }\n\n  let result;\n  try {\n    result = deps.spawn(\"npx\", [\"--yes\", \"skills\", \"find\", tech], {\n      timeout: NPX_TIMEOUT_MS,\n      killSignal: \"SIGKILL\",\n      encoding: \"utf8\",\n    });\n  } catch {\n    return \"\"; // fail-open: timeout kill/throw -> \"tech detected, no results\" branch\n  }\n\n  // F2: `spawnSync` does NOT throw when the binary itself is missing — it returns\n  // `{error: Error{code:'ENOENT'}, status: null, stdout: null}`. Left unhandled, that fell\n  // through to the SAME \"\" return as a genuine `{error: undefined, status: 0, stdout: \"\"}`\n  // (\"npx ran fine, found nothing\") — byte-identical, with no signal at all, unlike every\n  // other degraded path in this function (timeout, non-zero status: both fail open to \"\"\n  // too, but this is the one case where the failure mode itself — \"npx isn't even on\n  // PATH\" — is worth a distinct, loud diagnostic). Never cached either way.\n  if (result && result.error && result.error.code === \"ENOENT\") {\n    deps.warn(\"npx not found on PATH — skill discovery unavailable\");\n    return \"\";\n  }\n\n  // W2: `spawnSync` does NOT throw on timeout/failure — it returns `{error, status, stdout}`\n  // with a possibly non-empty PARTIAL stdout (a killed process's buffered output so far).\n  // Pre-fix, only `result.stdout` truthiness was checked, so a timed-out or failed `npx`\n  // yielded partial garbage that got sanitized, CACHED for 1h, and injected into the\n  // model's context inside the EXTERNAL DATA fence as if it were a genuine result.\n  if (result && (result.error || (typeof result.status === \"number\" && result.status !== 0))) {\n    return \"\";\n  }\n\n  const raw = (result && result.stdout) || \"\";\n  if (!raw) return \"\";\n  const clean = sanitizeNpxOutput(raw);\n  if (!clean) return \"\";\n\n  ensureDirSafe(deps, cacheDir);\n  try {\n    deps.fs.writeFileSync(cacheFile, clean);\n  } catch {\n    // caching is best-effort; not fatal\n  }\n  return clean;\n}\n\n\n/**\n * skill-enforcer — OpenCode plugin (installed by router-skills)\n *\n * PLUGIN SHELL ONLY. This file's scorer identifiers (STOPWORDS, AMBIENT, tokenize,\n * scoreGate, scoreRouter, classify, loadIndex, defaultDeps, skillsIndexPath, STRONG,\n * SOFT_MIN, and friends) are NOT imported here — they are supplied by `router-core.mjs`,\n * de-exported and prepended verbatim by `scripts/gen-templates.mjs` at generate time\n * (see design.md's D6). This file is NEVER used standalone; only the composed\n * `PLUGIN_TS` string constant (core + this shell) is shipped and copied to\n * `~/.config/opencode/plugins/skill-enforcer.ts`.\n *\n * Real skill-gate (parity with the Claude Code skill-gate hooks), now with the SAME\n * scoring math as Claude Code (no more hand-copied, drifted scorer — that drift, an\n * incomplete STOPWORDS set missing the accented \"también\", is exactly the bug this\n * unification closes). Four pieces:\n *   1. Deterministic contract  — score the user message, split into required\n *      (strong; enforced) and suggested (complementary; uncapped, never blocked).\n *   2. Gate (tool.execute.before) — block the first \"work\" tool until the\n *      required skills are loaded. Real enforcement, not advisory text.\n *   3. Aggressive auto-inject  — inline the top-2 SKILL.md bodies into the\n *      system prompt so the guidance is present even before any skill call.\n *   4. Router advisory (NEW)  — opencode gains router-level suggestions (the same\n *      `scoreRouter`+`classify` Claude Code's skill-router.mjs uses) for the first\n *      time, injected as a complementary, non-enforced advisory block.\n *\n * Fail-open: every hook except the intentional gate throw is wrapped so a plugin\n * error can never break the chat pipeline. Auto-loaded from ~/.config/opencode/plugins/.\n */\n\nimport type { Plugin } from \"@opencode-ai/plugin\"\n\nconst CORE_DEPS = defaultDeps()\nconst SKILL_INDEX_PATH = skillsIndexPath(CORE_DEPS)\nconst HOME = nodeHomedir()\nconst SKILL_DIRS = [\n  nodePath.join(HOME, \".config\", \"opencode\", \"skills\"),\n  nodePath.join(HOME, \".claude\", \"skills\"),\n  nodePath.join(HOME, \".agents\", \"skills\"),\n]\n\nconst WORK_TOOLS = new Set([\"write\", \"edit\", \"patch\", \"bash\", \"multiedit\"])\nconst MARKER = \"MANDATORY SKILL EVALUATION\"\n\n// ---- index loading (mirror of skill-gate-lib.mjs's real-fs adapter) ---------\n\n// C1: THE ORIGINAL BUG, reintroduced verbatim for opencode. `ensureIndex()` is what\n// actually BUILDS the on-disk index — its only call sites used to be Claude-only\n// (installClaude, skill-gate-eval.mjs, skill-router.mjs). An opencode-only user (no\n// Claude Code installed at all) got NO index from anyone: `loadIndex` read a file that was\n// never written -> `[]` -> `if (INDEX_CACHE) return INDEX_CACHE` cached it FOREVER (arrays\n// are always truthy in JS — the old comment claiming \"[] is truthy\" was describing a\n// symptom, not this module's real bug) -> `scoreGate` always `[]` -> the tool gate NEVER\n// fires, silently, for the entire life of the plugin process, with no opencode equivalent\n// of `[ROUTER WARNING]`/`[GATE WARNING]` anywhere in this file.\n//\n// Fixed: `getIndex()` now calls `ensureIndex(CORE_DEPS)` itself (the plugin is the only\n// thing that will ever run for an opencode-only install), caches ONLY a genuinely\n// non-empty index (an explicit `!== null` check on the cache slot itself — never inferred\n// from array truthiness), and computes a LOUD `INDEX_WARNING` whenever the index build\n// failed or is still empty. Not caching the empty state means a later chat turn in the\n// SAME process self-heals automatically once skills actually appear on disk (e.g. a\n// Claude Code hook builds it in parallel, or the user runs router-skills mid-session) —\n// never stuck silently broken for the process lifetime again.\nlet INDEX_CACHE: { name: string; desc: string }[] | null = null\nlet INDEX_WARNING = \"\"\nfunction getIndex(): { name: string; desc: string }[] {\n  if (INDEX_CACHE !== null) return INDEX_CACHE\n  const info = ensureIndex(CORE_DEPS)\n  const idx = loadIndex(SKILL_INDEX_PATH, CORE_DEPS)\n  if (info.indexError) {\n    INDEX_WARNING = `[SKILL GATE WARNING] index build failed (${info.indexError}) — enforcement INACTIVE.`\n  } else if (idx.length === 0) {\n    INDEX_WARNING = \"[SKILL GATE WARNING] no skills installed yet — enforcement INACTIVE. Corré `router-skills` o `npx skills add ...`.\"\n  } else {\n    INDEX_WARNING = \"\"\n  }\n  if (idx.length > 0) INDEX_CACHE = idx // never cache an empty/failed build permanently\n  return idx\n}\n\nfunction readSkillBody(name: string, maxChars = 2500): string {\n  for (const dir of SKILL_DIRS) {\n    const p = nodePath.join(dir, name, \"SKILL.md\")\n    if (nodeFs.existsSync(p)) {\n      const body = nodeFs.readFileSync(p, \"utf8\").trim()\n      return body.length > maxChars ? body.slice(0, maxChars) + \"\\n…[truncated]\" : body\n    }\n  }\n  return \"\"\n}\n\n// ---- per-session turn state -------------------------------------------------\n\ntype TurnState = {\n  required: string[]\n  suggested: string[]\n  routerRequired: string[]\n  routerSuggested: string[]\n  loaded: Set<string>\n  blocked: boolean\n}\nconst SESSIONS = new Map<string, TurnState>()\nlet LAST: TurnState | null = null // fallback bridge chat.message → system.transform\n\nfunction stateFor(sessionID?: string): TurnState {\n  const key = sessionID || \"__last__\"\n  let s = SESSIONS.get(key)\n  if (!s) {\n    s = { required: [], suggested: [], routerRequired: [], routerSuggested: [], loaded: new Set(), blocked: false }\n    SESSIONS.set(key, s)\n  }\n  return s\n}\n\nfunction textFromParts(parts: any[]): string {\n  if (!Array.isArray(parts)) return \"\"\n  return parts\n    .filter((p) => p && (p.type === \"text\" || typeof p.text === \"string\"))\n    .map((p) => p.text || \"\")\n    .join(\" \")\n}\n\nconst DIRECTIVE = `## ${MARKER} (a tool gate enforces the required set)\n\nLoad every skill that genuinely helps THIS task BEFORE running work tools\n(write/edit/bash). There is NO limit — if several skills complement each other,\nload ALL of them. The first work tool is BLOCKED until the required set is\nloaded. Naming a skill without loading it is worthless.`\n\nexport const SkillEnforcer: Plugin = async () => {\n  return {\n    // Piece 1: score the incoming user message (gate math), arm the turn contract.\n    // Piece 4 (NEW): ALSO score router-level (scoreRouter+classify) for an advisory\n    // block — opencode gaining router-level suggestions for the first time (AC-13).\n    \"chat.message\": async (_input: any, output: any) => {\n      try {\n        const parts = output?.parts ?? output?.message?.parts ?? []\n        const text = textFromParts(parts)\n        const idx = getIndex()\n        const { required, suggested } = classify(scoreGate(text, idx))\n        const { required: routerRequired, suggested: routerSuggested } = classify(scoreRouter(text, idx, CORE_DEPS))\n        const s = stateFor(output?.message?.sessionID)\n        s.required = required\n        s.suggested = suggested\n        s.routerRequired = routerRequired\n        s.routerSuggested = routerSuggested\n        s.loaded = new Set()\n        s.blocked = false\n        LAST = s\n      } catch {\n        // fail open — never break message handling\n      }\n    },\n\n    // Pieces 1 + 3 + 4: inject directive + required + suggested + top-2 skill bodies +\n    // the router advisory block (complementary, never gate-enforced).\n    \"experimental.chat.system.transform\": async (_input: any, output: any) => {\n      try {\n        if (!output || typeof output !== \"object\") return\n        const sys: any[] = Array.isArray(output.system) ? output.system : (output.system = [])\n        if (sys.some((x) => typeof x === \"string\" && x.includes(MARKER))) return // idempotent\n        const s = LAST\n        let block = DIRECTIVE\n        // C1: a LOUD, never-silent warning when the index is empty or failed to build —\n        // the exact bug this whole change exists to kill, now closed for opencode too.\n        if (INDEX_WARNING) block += `\\n\\n${INDEX_WARNING}`\n        if (s && s.required.length > 0) {\n          block += `\\n\\nREQUIRED_SKILLS (strong match — a work tool is blocked until each is loaded):\\n  ${s.required.join(\", \")}`\n        }\n        if (s && s.suggested.length > 0) {\n          block += `\\n\\nSUGGESTED_SKILLS (complementary — NOT enforced, but load every one that genuinely helps; combining several is expected):\\n  ${s.suggested.join(\", \")}`\n        }\n        if (s && (s.routerRequired.length > 0 || s.routerSuggested.length > 0)) {\n          block += `\\n\\nROUTER_SUGGESTIONS (advisory — router-level match, NOT gate-enforced, complementary to the required/suggested sets above):\\n  ${[...s.routerRequired, ...s.routerSuggested].join(\", \")}`\n        }\n        if (s && (s.required.length > 0 || s.suggested.length > 0)) {\n          const injected: string[] = []\n          for (const name of [...s.required, ...s.suggested].slice(0, 2)) {\n            const body = readSkillBody(name)\n            if (body) injected.push(`\\n----- AUTO-INJECTED SKILL: ${name} -----\\n${body}`)\n          }\n          if (injected.length > 0) {\n            block += `\\n\\nPre-loaded skill bodies (still call the skill tool so tooling runs):\\n${injected.join(\"\\n\")}`\n          }\n        }\n        const last = sys.length - 1\n        if (last >= 0 && typeof sys[last] === \"string\") sys[last] += \"\\n\\n\" + block\n        else sys.push(block)\n      } catch {\n        // fail open\n      }\n    },\n\n    // Piece 2 tracking: record skill loads.\n    \"tool.execute.after\": async (input: any, output: any) => {\n      try {\n        const tool = String(input?.tool || \"\").toLowerCase()\n        const s = stateFor(input?.sessionID)\n        if (tool.includes(\"skill\")) {\n          const arg = input?.args?.skill || input?.args?.name || output?.title || \"\"\n          if (arg) s.loaded.add(String(arg).trim().toLowerCase())\n        }\n        if (s.required.some((r) => r.toLowerCase() === tool)) s.loaded.add(tool)\n      } catch {\n        // fail open\n      }\n    },\n\n    // Piece 2 gate: block the first work tool until required skills are loaded.\n    // The scoring is fail-open (errors → no block); the block itself is intentional.\n    \"tool.execute.before\": async (input: any, _output: any) => {\n      let missing: string[] = []\n      try {\n        const tool = String(input?.tool || \"\").toLowerCase()\n        if (!WORK_TOOLS.has(tool)) return\n        const s = stateFor(input?.sessionID)\n        if (s.required.length === 0 || s.blocked) return\n        missing = s.required.filter((r) => !s.loaded.has(r.toLowerCase()))\n        if (missing.length === 0) return\n        s.blocked = true // one block per turn — never deadlock\n      } catch {\n        return // fail open — a scorer error must never block work\n      }\n      throw new Error(\n        `SKILL GATE: cargá las skills OBLIGATORIAS de este turno antes de trabajar: ${missing.join(\", \")}. ` +\n          `Usá la herramienta de skills con cada una y volvé a intentar. No las anuncies: cargalas de verdad.`,\n      )\n    },\n  }\n}\n\nexport default SkillEnforcer\n"

export const SKILL_RULE_MD = "# MANDATORY SKILL EVALUATION (a gate enforces the required set)\n\nYou have a large catalog of Agent Skills discovered globally. Before answering a\ntechnical request you MUST evaluate them and load every one that genuinely helps.\n\nRules:\n\n1. Load every skill that helps THIS task before running work tools\n   (write/edit/bash). There is NO limit — if several skills complement each\n   other, load ALL of them, not a token few.\n2. Prefer the MOST SPECIFIC skill (e.g. `nextjs-best-practices`,\n   `laravel-security`) over a broad one (e.g. `coding-standards`) when both match.\n3. Do NOT keep reaching for the same handful of skills out of habit. Re-evaluate\n   the full catalog each turn; the best skill may be one you have never used.\n4. State in one line which you are loading and why, load each via the skill tool\n   BEFORE writing code, then proceed.\n5. If nothing genuinely fits, proceed directly — no forced match.\n\nA tool gate blocks your first work tool until the strongly-matched skills are\nloaded. Naming a skill without loading it is worthless.\n"

